  { "chinese": "谈判", "pinyin": "tánpàn", "translations": { "ru": "переговоры", "en": "negotiation" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "谈判进行得很顺利。", "pinyin": "Tánpàn jìnxíng de hěn shùnlì.", "translation": { "ru": "Переговоры проходят успешно.", "en": "The negotiation is going smoothly." }, "difficulty": "medium" }, { "chinese": "经过三轮艰难的谈判，双方终于在价格问题上达成了一致。", "pinyin": "Jīngguò sān lún jiānnán de tánpàn, shuāngfāng zhōngyú zài jiàgé wèntí shàng dáchéngle yīzhì.", "translation": { "ru": "После трёх раундов сложных переговоров стороны наконец пришли к согласию по вопросу цены.", "en": "After three rounds of tough negotiations, both sides finally reached agreement on the price issue." }, "difficulty": "hard" }] },
  { "chinese": "客户", "pinyin": "kèhù", "translations": { "ru": "клиент", "en": "client, customer" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这是我们的重要客户。", "pinyin": "Zhè shì wǒmen de zhòngyào kèhù.", "translation": { "ru": "Это наш важный клиент.", "en": "This is our important client." }, "difficulty": "easy" }, { "chinese": "客户满意度调查显示，百分之九十的客户对我们的服务表示满意。", "pinyin": "Kèhù mǎnyìdù diàochá xiǎnshì, bǎifēn zhī jiǔshí de kèhù duì wǒmen de fúwù biǎoshì mǎnyì.", "translation": { "ru": "Опрос удовлетворённости показал, что 90% клиентов довольны нашим сервисом.", "en": "The customer satisfaction survey shows that 90% of clients are satisfied with our service." }, "difficulty": "hard" }] },
  { "chinese": "顾客", "pinyin": "gùkè", "translations": { "ru": "покупатель, посетитель", "en": "customer, patron" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "顾客永远是对的。", "pinyin": "Gùkè yǒngyuǎn shì duì de.", "translation": { "ru": "Покупатель всегда прав.", "en": "The customer is always right." }, "difficulty": "easy" }, { "chinese": "为了吸引更多顾客，商场推出了会员积分优惠活动。", "pinyin": "Wèile xīyǐn gèng duō gùkè, shāngchǎng tuīchūle huìyuán jīfēn yōuhuì huódòng.", "translation": { "ru": "Чтобы привлечь больше покупателей, торговый центр запустил программу лояльности с бонусными баллами.", "en": "To attract more customers, the mall launched a membership points promotion." }, "difficulty": "hard" }] },
  { "chinese": "供应商", "pinyin": "gōngyìngshāng", "translations": { "ru": "поставщик", "en": "supplier, vendor" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "我们需要找新的供应商。", "pinyin": "Wǒmen xūyào zhǎo xīn de gōngyìngshāng.", "translation": { "ru": "Нам нужно найти нового поставщика.", "en": "We need to find a new supplier." }, "difficulty": "medium" }, { "chinese": "公司正在对所有供应商进行资质审核，以确保供应链的稳定性。", "pinyin": "Gōngsī zhèngzài duì suǒyǒu gōngyìngshāng jìnxíng zīzhì shěnhé, yǐ quèbǎo gōngyìngliàn de wěndìngxìng.", "translation": { "ru": "Компания проводит проверку квалификации всех поставщиков для обеспечения стабильности цепочки поставок.", "en": "The company is conducting qualification reviews of all suppliers to ensure supply chain stability." }, "difficulty": "hard" }] },
  { "chinese": "合伙人", "pinyin": "héhuǒrén", "translations": { "ru": "партнёр, компаньон", "en": "partner" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "他是我的商业合伙人。", "pinyin": "Tā shì wǒ de shāngyè héhuǒrén.", "translation": { "ru": "Он мой деловой партнёр.", "en": "He is my business partner." }, "difficulty": "easy" }, { "chinese": "合伙人之间的分歧导致公司面临分裂的危机。", "pinyin": "Héhuǒrén zhījiān de fēnqí dǎozhì gōngsī miànlín fēnliè de wēijī.", "translation": { "ru": "Разногласия между партнёрами привели к угрозе раскола компании.", "en": "Disagreements between partners led to a crisis of the company splitting up." }, "difficulty": "hard" }] },
  { "chinese": "竞争对手", "pinyin": "jìngzhēng duìshǒu", "translations": { "ru": "конкурент", "en": "competitor" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "我们最大的竞争对手是谁？", "pinyin": "Wǒmen zuìdà de jìngzhēng duìshǒu shì shéi?", "translation": { "ru": "Кто наш главный конкурент?", "en": "Who is our biggest competitor?" }, "difficulty": "medium" }, { "chinese": "通过分析竞争对手的产品和定价策略，我们找到了市场突破口。", "pinyin": "Tōngguò fēnxī jìngzhēng duìshǒu de chǎnpǐn hé dìngjià cèlüè, wǒmen zhǎodàole shìchǎng tūpòkǒu.", "translation": { "ru": "Проанализировав продукцию и ценовую стратегию конкурентов, мы нашли нишу на рынке.", "en": "By analyzing competitors' products and pricing strategies, we found a market breakthrough." }, "difficulty": "hard" }] },
  { "chinese": "市场", "pinyin": "shìchǎng", "translations": { "ru": "рынок", "en": "market" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "中国市场很大。", "pinyin": "Zhōngguó shìchǎng hěn dà.", "translation": { "ru": "Китайский рынок очень большой.", "en": "The Chinese market is very large." }, "difficulty": "easy" }, { "chinese": "公司计划明年进入东南亚市场，目前正在做市场调研。", "pinyin": "Gōngsī jìhuà míngnián jìnrù dōngnányà shìchǎng, mùqián zhèngzài zuò shìchǎng diàoyán.", "translation": { "ru": "Компания планирует выйти на рынок Юго-Восточной Азии в следующем году и сейчас проводит маркетинговые исследования.", "en": "The company plans to enter the Southeast Asian market next year and is currently conducting market research." }, "difficulty": "hard" }] },
  { "chinese": "价格", "pinyin": "jiàgé", "translations": { "ru": "цена", "en": "price" }, "difficulty": "easy", "hskLevel": 2, "tags": ["business", "general"], "examples": [{ "chinese": "这个价格太贵了。", "pinyin": "Zhège jiàgé tài guì le.", "translation": { "ru": "Эта цена слишком высокая.", "en": "This price is too expensive." }, "difficulty": "easy" }, { "chinese": "由于供不应求，原材料的价格在过去半年里涨了一倍。", "pinyin": "Yóuyú gōng bù yìng qiú, yuáncáiliào de jiàgé zài guòqù bànnián lǐ zhǎngle yī bèi.", "translation": { "ru": "Из-за дефицита предложения цены на сырьё за полгода выросли вдвое.", "en": "Due to supply shortages, raw material prices have doubled in the past six months." }, "difficulty": "hard" }] },
  { "chinese": "成本", "pinyin": "chéngběn", "translations": { "ru": "себестоимость, затраты", "en": "cost" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我们要降低成本。", "pinyin": "Wǒmen yào jiàngdī chéngběn.", "translation": { "ru": "Нам нужно снизить затраты.", "en": "We need to reduce costs." }, "difficulty": "easy" }, { "chinese": "自动化生产线的引入大幅降低了人工成本和出错率。", "pinyin": "Zìdònghuà shēngchǎnxiàn de yǐnrù dàfú jiàngdīle réngōng chéngběn hé chūcuòlǜ.", "translation": { "ru": "Внедрение автоматизированной линии значительно сократило затраты на рабочую силу и процент брака.", "en": "The introduction of automated production lines greatly reduced labor costs and error rates." }, "difficulty": "hard" }] },
  { "chinese": "折扣", "pinyin": "zhékòu", "translations": { "ru": "скидка", "en": "discount" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "能给我打个折扣吗？", "pinyin": "Néng gěi wǒ dǎ ge zhékòu ma?", "translation": { "ru": "Можете дать мне скидку?", "en": "Can you give me a discount?" }, "difficulty": "easy" }, { "chinese": "批量采购可以享受八折优惠，订单越大折扣越多。", "pinyin": "Pīliàng cǎigòu kěyǐ xiǎngshòu bā zhé yōuhuì, dìngdān yuè dà zhékòu yuè duō.", "translation": { "ru": "При оптовой закупке предоставляется скидка 20%, чем больше заказ — тем больше скидка.", "en": "Bulk purchases enjoy a 20% discount, the larger the order, the bigger the discount." }, "difficulty": "hard" }] },
  { "chinese": "税", "pinyin": "shuì", "translations": { "ru": "налог", "en": "tax" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "你交税了吗？", "pinyin": "Nǐ jiāo shuì le ma?", "translation": { "ru": "Ты заплатил налоги?", "en": "Have you paid your taxes?" }, "difficulty": "easy" }, { "chinese": "新的税收政策对小型企业减免了部分增值税。", "pinyin": "Xīn de shuìshōu zhèngcè duì xiǎoxíng qǐyè jiǎnmiǎnle bùfèn zēngzhíshuì.", "translation": { "ru": "Новая налоговая политика освобождает малые предприятия от части НДС.", "en": "The new tax policy exempts small businesses from part of the value-added tax." }, "difficulty": "hard" }] },
  { "chinese": "发票", "pinyin": "fāpiào", "translations": { "ru": "счёт-фактура, чек", "en": "invoice, receipt" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "请给我开一张发票。", "pinyin": "Qǐng gěi wǒ kāi yī zhāng fāpiào.", "translation": { "ru": "Пожалуйста, выпишите мне счёт-фактуру.", "en": "Please issue me an invoice." }, "difficulty": "easy" }, { "chinese": "公司规定所有报销必须附上正规发票，否则不予处理。", "pinyin": "Gōngsī guīdìng suǒyǒu bàoxiāo bìxū fùshàng zhèngguī fāpiào, fǒuzé bù yǔ chǔlǐ.", "translation": { "ru": "Правила компании требуют прикладывать официальные счета-фактуры ко всем возмещениям расходов.", "en": "Company policy requires all reimbursements to be accompanied by official invoices." }, "difficulty": "hard" }] },
  { "chinese": "收据", "pinyin": "shōujù", "translations": { "ru": "квитанция, расписка", "en": "receipt" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "请给我一张收据。", "pinyin": "Qǐng gěi wǒ yī zhāng shōujù.", "translation": { "ru": "Дайте мне, пожалуйста, квитанцию.", "en": "Please give me a receipt." }, "difficulty": "easy" }, { "chinese": "付款后请妥善保管收据，以备退换货时使用。", "pinyin": "Fùkuǎn hòu qǐng tuǒshàn bǎoguǎn shōujù, yǐ bèi tuìhuànhuò shí shǐyòng.", "translation": { "ru": "После оплаты сохраните квитанцию на случай возврата или обмена товара.", "en": "Please keep the receipt safe after payment for possible returns or exchanges." }, "difficulty": "hard" }] },
  { "chinese": "付款", "pinyin": "fùkuǎn", "translations": { "ru": "оплата, платёж", "en": "payment" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "请尽快付款。", "pinyin": "Qǐng jǐnkuài fùkuǎn.", "translation": { "ru": "Пожалуйста, оплатите как можно скорее.", "en": "Please make the payment as soon as possible." }, "difficulty": "easy" }, { "chinese": "合同约定分三期付款，首付百分之三十，剩余分两次支付。", "pinyin": "Hétong yuēdìng fēn sān qī fùkuǎn, shǒufù bǎifēn zhī sānshí, shèngyú fēn liǎng cì zhīfù.", "translation": { "ru": "По договору оплата производится в три этапа: аванс 30%, остаток — двумя платежами.", "en": "The contract stipulates payment in three installments: 30% upfront, the rest in two payments." }, "difficulty": "hard" }] },
  { "chinese": "送货", "pinyin": "sònghuò", "translations": { "ru": "доставка товара", "en": "delivery" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "送货是免费的吗？", "pinyin": "Sònghuò shì miǎnfèi de ma?", "translation": { "ru": "Доставка бесплатная?", "en": "Is delivery free?" }, "difficulty": "easy" }, { "chinese": "由于暴雨天气，部分地区的送货时间可能会延迟两到三天。", "pinyin": "Yóuyú bàoyǔ tiānqì, bùfèn dìqū de sònghuò shíjiān kěnéng huì yánchí liǎng dào sān tiān.", "translation": { "ru": "Из-за сильных дождей сроки доставки в некоторых районах могут задержаться на 2–3 дня.", "en": "Due to heavy rain, delivery times in some areas may be delayed by two to three days." }, "difficulty": "hard" }] },
  { "chinese": "订单", "pinyin": "dìngdān", "translations": { "ru": "заказ", "en": "order" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "我收到了一个新订单。", "pinyin": "Wǒ shōudàole yī ge xīn dìngdān.", "translation": { "ru": "Я получил новый заказ.", "en": "I received a new order." }, "difficulty": "easy" }, { "chinese": "系统显示这个订单已经发货，预计后天到达。", "pinyin": "Xìtǒng xiǎnshì zhège dìngdān yǐjīng fāhuò, yùjì hòutiān dàodá.", "translation": { "ru": "Система показывает, что этот заказ уже отправлен и ожидается послезавтра.", "en": "The system shows this order has been shipped and is expected to arrive the day after tomorrow." }, "difficulty": "medium" }] },
  { "chinese": "库存", "pinyin": "kùcún", "translations": { "ru": "запасы, складские остатки", "en": "inventory, stock" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "库存不够了，需要补货。", "pinyin": "Kùcún bú gòu le, xūyào bǔhuò.", "translation": { "ru": "Запасов недостаточно, нужно пополнить.", "en": "The inventory is not enough, we need to restock." }, "difficulty": "medium" }, { "chinese": "仓库管理系统可以实时监控库存水平，自动触发补货通知。", "pinyin": "Cāngkù guǎnlǐ xìtǒng kěyǐ shíshí jiānkòng kùcún shuǐpíng, zìdòng chùfā bǔhuò tōngzhī.", "translation": { "ru": "Система управления складом позволяет отслеживать уровень запасов в реальном времени и автоматически отправлять уведомления о необходимости пополнения.", "en": "The warehouse management system can monitor inventory levels in real time and automatically trigger restocking notifications." }, "difficulty": "hard" }] },
  { "chinese": "盘点", "pinyin": "pándiǎn", "translations": { "ru": "инвентаризация", "en": "stocktaking, inventory check" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "月底要做一次盘点。", "pinyin": "Yuèdǐ yào zuò yī cì pándiǎn.", "translation": { "ru": "В конце месяца нужно провести инвентаризацию.", "en": "We need to do a stocktaking at the end of the month." }, "difficulty": "medium" }, { "chinese": "盘点结果显示仓库的实际库存与系统记录存在较大差异。", "pinyin": "Pándiǎn jiéguǒ xiǎnshì cāngkù de shíjì kùcún yǔ xìtǒng jìlù cúnzài jiào dà chāyì.", "translation": { "ru": "Результаты инвентаризации показали значительные расхождения между фактическими запасами и данными системы.", "en": "The stocktaking results show significant discrepancies between actual inventory and system records." }, "difficulty": "hard" }] },
  { "chinese": "仓库", "pinyin": "cāngkù", "translations": { "ru": "склад", "en": "warehouse" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "货物已经到仓库了。", "pinyin": "Huòwù yǐjīng dào cāngkù le.", "translation": { "ru": "Товар уже на складе.", "en": "The goods have arrived at the warehouse." }, "difficulty": "easy" }, { "chinese": "公司在上海郊区租了一个两千平方米的仓库用于存放出口商品。", "pinyin": "Gōngsī zài Shànghǎi jiāoqū zūle yī ge liǎngqiān píngfāngmǐ de cāngkù yòngyú cúnfàng chūkǒu shāngpǐn.", "translation": { "ru": "Компания арендовала склад площадью 2000 кв.м. в пригороде Шанхая для хранения экспортных товаров.", "en": "The company rented a 2,000 square meter warehouse in suburban Shanghai to store export goods." }, "difficulty": "hard" }] },
  { "chinese": "工厂", "pinyin": "gōngchǎng", "translations": { "ru": "фабрика, завод", "en": "factory" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "这家工厂有两百个工人。", "pinyin": "Zhè jiā gōngchǎng yǒu liǎngbǎi ge gōngrén.", "translation": { "ru": "На этой фабрике двести рабочих.", "en": "This factory has two hundred workers." }, "difficulty": "easy" }, { "chinese": "工厂引进了全自动化生产线，产能提升了百分之五十。", "pinyin": "Gōngchǎng yǐnjìnle quán zìdònghuà shēngchǎnxiàn, chǎnnéng tíshēngle bǎifēn zhī wǔshí.", "translation": { "ru": "Завод внедрил полностью автоматизированную линию, производительность выросла на 50%.", "en": "The factory introduced a fully automated production line, increasing capacity by 50%." }, "difficulty": "hard" }] },
  { "chinese": "生产", "pinyin": "shēngchǎn", "translations": { "ru": "производство, производить", "en": "production, to produce" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这家工厂生产手机。", "pinyin": "Zhè jiā gōngchǎng shēngchǎn shǒujī.", "translation": { "ru": "Эта фабрика производит мобильные телефоны.", "en": "This factory produces mobile phones." }, "difficulty": "easy" }, { "chinese": "为了满足市场需求，工厂决定将日生产量从一千台提高到一千五百台。", "pinyin": "Wèile mǎnzú shìchǎng xūqiú, gōngchǎng juédìng jiāng rì shēngchǎnliàng cóng yīqiān tái tígāo dào yīqiān wǔbǎi tái.", "translation": { "ru": "Чтобы удовлетворить рыночный спрос, завод решил увеличить дневное производство с 1000 до 1500 единиц.", "en": "To meet market demand, the factory decided to increase daily production from 1,000 to 1,500 units." }, "difficulty": "hard" }] },
  { "chinese": "质量", "pinyin": "zhìliàng", "translations": { "ru": "качество", "en": "quality" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "产品质量很好。", "pinyin": "Chǎnpǐn zhìliàng hěn hǎo.", "translation": { "ru": "Качество продукции отличное.", "en": "The product quality is very good." }, "difficulty": "easy" }, { "chinese": "质量管理体系的建立有助于减少产品缺陷率，提升客户满意度。", "pinyin": "Zhìliàng guǎnlǐ tǐxì de jiànlì yǒuzhùyú jiǎnshǎo chǎnpǐn quēxiànlǜ, tíshēng kèhù mǎnyìdù.", "translation": { "ru": "Внедрение системы управления качеством помогает снизить уровень дефектов и повысить удовлетворённость клиентов.", "en": "Establishing a quality management system helps reduce product defect rates and improve customer satisfaction." }, "difficulty": "hard" }] },
  { "chinese": "品牌", "pinyin": "pǐnpái", "translations": { "ru": "бренд, торговая марка", "en": "brand" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这是一个很有名的品牌。", "pinyin": "Zhè shì yī ge hěn yǒumíng de pǐnpái.", "translation": { "ru": "Это очень известный бренд.", "en": "This is a very famous brand." }, "difficulty": "easy" }, { "chinese": "企业在品牌建设方面投入了大量资金，以提升品牌的国际影响力。", "pinyin": "Qǐyè zài pǐnpái jiànshè fāngmiàn tóurùle dàliàng zījīn, yǐ tíshēng pǐnpái de guójì yǐngxiǎnglì.", "translation": { "ru": "Предприятие вложило значительные средства в построение бренда для повышения его международного влияния.", "en": "The enterprise invested heavily in brand building to enhance its international influence." }, "difficulty": "hard" }] },
  { "chinese": "商标", "pinyin": "shāngbiāo", "translations": { "ru": "товарный знак", "en": "trademark" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我们注册了商标。", "pinyin": "Wǒmen zhùcèle shāngbiāo.", "translation": { "ru": "Мы зарегистрировали товарный знак.", "en": "We registered the trademark." }, "difficulty": "easy" }, { "chinese": "未经授权使用他人注册商标属于侵权行为，可能面临法律诉讼。", "pinyin": "Wèi jīng shòuquán shǐyòng tārén zhùcè shāngbiāo shǔyú qīnquán xíngwéi, kěnéng miànlín fǎlǜ sùsòng.", "translation": { "ru": "Несанкционированное использование чужого зарегистрированного товарного знака является нарушением прав и может привести к судебному иску.", "en": "Unauthorized use of another's registered trademark constitutes infringement and may lead to litigation." }, "difficulty": "hard" }] },
  { "chinese": "广告", "pinyin": "guǎnggào", "translations": { "ru": "реклама", "en": "advertisement, advertising" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "我在电视上看到了这个广告。", "pinyin": "Wǒ zài diànshì shàng kàndàole zhège guǎnggào.", "translation": { "ru": "Я видел эту рекламу по телевизору.", "en": "I saw this advertisement on TV." }, "difficulty": "easy" }, { "chinese": "公司把大部分营销预算投入到了社交媒体广告上。", "pinyin": "Gōngsī bǎ dàbùfèn yíngxiāo yùsuàn tóurù dàole shèjiāo méitǐ guǎnggào shàng.", "translation": { "ru": "Компания вложила большую часть маркетингового бюджета в рекламу в социальных сетях.", "en": "The company invested most of its marketing budget in social media advertising." }, "difficulty": "hard" }] },
  { "chinese": "营销", "pinyin": "yíngxiāo", "translations": { "ru": "маркетинг", "en": "marketing" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "他在营销部门工作。", "pinyin": "Tā zài yíngxiāo bùmén gōngzuò.", "translation": { "ru": "Он работает в отделе маркетинга.", "en": "He works in the marketing department." }, "difficulty": "easy" }, { "chinese": "数字营销已经成为企业获取新客户的最重要渠道之一。", "pinyin": "Shùzì yíngxiāo yǐjīng chéngwéi qǐyè huòqǔ xīn kèhù de zuì zhòngyào qúdào zhī yī.", "translation": { "ru": "Цифровой маркетинг стал одним из важнейших каналов привлечения новых клиентов.", "en": "Digital marketing has become one of the most important channels for acquiring new customers." }, "difficulty": "hard" }] },
  { "chinese": "销售", "pinyin": "xiāoshòu", "translations": { "ru": "продажа", "en": "sales" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这个月的销售额很高。", "pinyin": "Zhège yuè de xiāoshòu'é hěn gāo.", "translation": { "ru": "Объём продаж в этом месяце очень высокий.", "en": "This month's sales are very high." }, "difficulty": "easy" }, { "chinese": "销售团队通过精准的客户定位和跟进策略，超额完成了季度目标。", "pinyin": "Xiāoshòu tuánduì tōngguò jīngzhǔn de kèhù dìngwèi hé gēnjìn cèlüè, chāo'é wánchéngle jìdù mùbiāo.", "translation": { "ru": "Отдел продаж перевыполнил квартальный план благодаря точному таргетированию клиентов и стратегии сопровождения.", "en": "The sales team exceeded quarterly targets through precise customer targeting and follow-up strategies." }, "difficulty": "hard" }] },
  { "chinese": "采购", "pinyin": "cǎigòu", "translations": { "ru": "закупка", "en": "procurement, purchasing" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我们需要采购一批新设备。", "pinyin": "Wǒmen xūyào cǎigòu yī pī xīn shèbèi.", "translation": { "ru": "Нам нужно закупить партию нового оборудования.", "en": "We need to purchase a batch of new equipment." }, "difficulty": "medium" }, { "chinese": "采购部正在比较不同供应商的报价，以选择性价比最高的方案。", "pinyin": "Cǎigòu bù zhèngzài bǐjiào bùtóng gōngyìngshāng de bàojià, yǐ xuǎnzé xìngjiàbǐ zuìgāo de fāng'àn.", "translation": { "ru": "Отдел закупок сравнивает предложения разных поставщиков, чтобы выбрать оптимальный вариант.", "en": "The procurement department is comparing quotes from different suppliers to select the best value option." }, "difficulty": "hard" }] },
  { "chinese": "出口", "pinyin": "chūkǒu", "translations": { "ru": "экспорт", "en": "export" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "中国出口很多商品。", "pinyin": "Zhōngguó chūkǒu hěn duō shāngpǐn.", "translation": { "ru": "Китай экспортирует много товаров.", "en": "China exports a lot of goods." }, "difficulty": "easy" }, { "chinese": "公司的出口业务已经覆盖了三十多个国家和地区。", "pinyin": "Gōngsī de chūkǒu yèwù yǐjīng fùgàile sānshí duō ge guójiā hé dìqū.", "translation": { "ru": "Экспортная деятельность компании охватывает более 30 стран и регионов.", "en": "The company's export business covers more than 30 countries and regions." }, "difficulty": "hard" }] },
  { "chinese": "进口", "pinyin": "jìnkǒu", "translations": { "ru": "импорт", "en": "import" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这些设备是从德国进口的。", "pinyin": "Zhèxiē shèbèi shì cóng Déguó jìnkǒu de.", "translation": { "ru": "Это оборудование импортировано из Германии.", "en": "This equipment is imported from Germany." }, "difficulty": "easy" }, { "chinese": "政府决定降低部分进口商品的关税，以促进国际贸易。", "pinyin": "Zhèngfǔ juédìng jiàngdī bùfèn jìnkǒu shāngpǐn de guānshuì, yǐ cùjìn guójì màoyì.", "translation": { "ru": "Правительство решило снизить пошлины на ряд импортных товаров для стимулирования международной торговли.", "en": "The government decided to lower tariffs on some imported goods to promote international trade." }, "difficulty": "hard" }] },
  { "chinese": "贸易", "pinyin": "màoyì", "translations": { "ru": "торговля", "en": "trade" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "国际贸易越来越重要。", "pinyin": "Guójì màoyì yuèláiyuè zhòngyào.", "translation": { "ru": "Международная торговля становится всё важнее.", "en": "International trade is becoming increasingly important." }, "difficulty": "easy" }, { "chinese": "两国签署了自由贸易协定，取消了大部分商品的进口关税。", "pinyin": "Liǎng guó qiānshǔle zìyóu màoyì xiédìng, qǔxiāole dàbùfèn shāngpǐn de jìnkǒu guānshuì.", "translation": { "ru": "Две страны подписали соглашение о свободной торговле, отменив импортные пошлины на большинство товаров.", "en": "The two countries signed a free trade agreement, eliminating import tariffs on most goods." }, "difficulty": "hard" }] },
  { "chinese": "物流", "pinyin": "wùliú", "translations": { "ru": "логистика", "en": "logistics" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "物流公司负责运输货物。", "pinyin": "Wùliú gōngsī fùzé yùnshū huòwù.", "translation": { "ru": "Логистическая компания отвечает за перевозку грузов.", "en": "The logistics company is responsible for transporting goods." }, "difficulty": "easy" }, { "chinese": "高效的物流体系是电子商务成功的关键因素之一。", "pinyin": "Gāoxiào de wùliú tǐxì shì diànzǐ shāngwù chénggōng de guānjiàn yīnsù zhī yī.", "translation": { "ru": "Эффективная логистическая система — один из ключевых факторов успеха электронной коммерции.", "en": "An efficient logistics system is one of the key factors for e-commerce success." }, "difficulty": "hard" }] },
  { "chinese": "运输", "pinyin": "yùnshū", "translations": { "ru": "транспортировка, перевозка", "en": "transportation, shipping" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "货物正在运输中。", "pinyin": "Huòwù zhèngzài yùnshū zhōng.", "translation": { "ru": "Товар в пути.", "en": "The goods are being transported." }, "difficulty": "easy" }, { "chinese": "海运的运输成本比空运低很多，但运输时间较长。", "pinyin": "Hǎiyùn de yùnshū chéngběn bǐ kōngyùn dī hěn duō, dàn yùnshū shíjiān jiào cháng.", "translation": { "ru": "Стоимость морской перевозки намного ниже воздушной, но сроки доставки дольше.", "en": "Sea freight costs are much lower than air freight, but the shipping time is longer." }, "difficulty": "hard" }] },
  { "chinese": "保险", "pinyin": "bǎoxiǎn", "translations": { "ru": "страхование, страховка", "en": "insurance" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "你买保险了吗？", "pinyin": "Nǐ mǎi bǎoxiǎn le ma?", "translation": { "ru": "Ты купил страховку?", "en": "Have you bought insurance?" }, "difficulty": "easy" }, { "chinese": "公司为所有员工购买了商业医疗保险和意外伤害保险。", "pinyin": "Gōngsī wèi suǒyǒu yuángōng gòumǎile shāngyè yīliáo bǎoxiǎn hé yìwài shānghài bǎoxiǎn.", "translation": { "ru": "Компания оформила для всех сотрудников коммерческую медицинскую страховку и страховку от несчастных случаев.", "en": "The company purchased commercial medical insurance and accident insurance for all employees." }, "difficulty": "hard" }] },
  { "chinese": "执照", "pinyin": "zhízhào", "translations": { "ru": "лицензия", "en": "license" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "开店需要营业执照。", "pinyin": "Kāi diàn xūyào yíngyè zhízhào.", "translation": { "ru": "Для открытия магазина нужна лицензия на ведение бизнеса.", "en": "A business license is needed to open a store." }, "difficulty": "easy" }, { "chinese": "由于未取得相关经营执照，该餐厅被市场监管部门责令停业整改。", "pinyin": "Yóuyú wèi qǔdé xiāngguān jīngyíng zhízhào, gāi cāntīng bèi shìchǎng jiānguǎn bùmén zélìng tíngyè zhěnggǎi.", "translation": { "ru": "Из-за отсутствия соответствующей лицензии ресторан был закрыт на исправление по требованию надзорного органа.", "en": "Due to not having the relevant business license, the restaurant was ordered to close for rectification." }, "difficulty": "hard" }] },
  { "chinese": "许可证", "pinyin": "xǔkězhèng", "translations": { "ru": "разрешение, допуск", "en": "permit, license" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "进口食品需要许可证。", "pinyin": "Jìnkǒu shípǐn xūyào xǔkězhèng.", "translation": { "ru": "Для импорта продуктов питания нужно разрешение.", "en": "Importing food requires a permit." }, "difficulty": "medium" }, { "chinese": "企业在申请排污许可证时，必须提交环境影响评估报告。", "pinyin": "Qǐyè zài shēnqǐng páiwū xǔkězhèng shí, bìxū tíjiāo huánjìng yǐngxiǎng pínggū bàogào.", "translation": { "ru": "При подаче заявки на разрешение на выбросы предприятие обязано предоставить отчёт об оценке воздействия на окружающую среду.", "en": "When applying for a pollution discharge permit, enterprises must submit an environmental impact assessment report." }, "difficulty": "hard" }] },
  { "chinese": "注册", "pinyin": "zhùcè", "translations": { "ru": "регистрация, зарегистрировать", "en": "registration, to register" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我想注册一家公司。", "pinyin": "Wǒ xiǎng zhùcè yī jiā gōngsī.", "translation": { "ru": "Я хочу зарегистрировать компанию.", "en": "I want to register a company." }, "difficulty": "easy" }, { "chinese": "在中国注册外资企业需要经过多个部门的审批手续。", "pinyin": "Zài Zhōngguó zhùcè wàizī qǐyè xūyào jīngguò duō ge bùmén de shěnpī shǒuxù.", "translation": { "ru": "Регистрация иностранного предприятия в Китае требует прохождения согласований в нескольких ведомствах.", "en": "Registering a foreign-funded enterprise in China requires approval procedures from multiple departments." }, "difficulty": "hard" }] },
  { "chinese": "审计", "pinyin": "shěnjì", "translations": { "ru": "аудит", "en": "audit" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司每年都要做审计。", "pinyin": "Gōngsī měi nián dōu yào zuò shěnjì.", "translation": { "ru": "Компания ежегодно проходит аудит.", "en": "The company undergoes an audit every year." }, "difficulty": "medium" }, { "chinese": "外部审计机构发现了财务报表中存在的若干重大错报。", "pinyin": "Wàibù shěnjì jīgòu fāxiànle cáiwù bàobiǎo zhōng cúnzài de ruògān zhòngdà cuòbào.", "translation": { "ru": "Внешняя аудиторская фирма обнаружила ряд существенных искажений в финансовой отчётности.", "en": "The external audit firm found several material misstatements in the financial statements." }, "difficulty": "hard" }] },
  { "chinese": "报告", "pinyin": "bàogào", "translations": { "ru": "отчёт, доклад", "en": "report" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "请写一份报告。", "pinyin": "Qǐng xiě yī fèn bàogào.", "translation": { "ru": "Пожалуйста, напишите отчёт.", "en": "Please write a report." }, "difficulty": "easy" }, { "chinese": "年度报告详细分析了公司在过去一年中的经营状况和财务表现。", "pinyin": "Niándù bàogào xiángxì fēnxīle gōngsī zài guòqù yī nián zhōng de jīngyíng zhuàngkuàng hé cáiwù biǎoxiàn.", "translation": { "ru": "Годовой отчёт подробно проанализировал операционную деятельность и финансовые показатели компании за прошлый год.", "en": "The annual report provided a detailed analysis of the company's operations and financial performance over the past year." }, "difficulty": "hard" }] },
  { "chinese": "汇报", "pinyin": "huìbào", "translations": { "ru": "докладывать, отчитываться", "en": "to report, to brief" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我去跟经理汇报工作。", "pinyin": "Wǒ qù gēn jīnglǐ huìbào gōngzuò.", "translation": { "ru": "Я пойду доложу менеджеру о работе.", "en": "I'll go report to the manager." }, "difficulty": "easy" }, { "chinese": "每周一上午各部门负责人要向总经理汇报上周的工作进展。", "pinyin": "Měi zhōuyī shàngwǔ gè bùmén fùzérén yào xiàng zǒngjīnglǐ huìbào shàng zhōu de gōngzuò jìnzhǎn.", "translation": { "ru": "Каждый понедельник утром руководители отделов отчитываются генеральному директору о ходе работы за прошлую неделю.", "en": "Every Monday morning, department heads report last week's progress to the general manager." }, "difficulty": "hard" }] },
  { "chinese": "演示", "pinyin": "yǎnshì", "translations": { "ru": "презентация, демонстрация", "en": "presentation, demonstration" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "请看一下这个产品演示。", "pinyin": "Qǐng kàn yīxià zhège chǎnpǐn yǎnshì.", "translation": { "ru": "Посмотрите, пожалуйста, демонстрацию продукта.", "en": "Please watch this product demonstration." }, "difficulty": "easy" }, { "chinese": "他准备了一份精美的幻灯片，在客户面前做了一次成功的项目演示。", "pinyin": "Tā zhǔnbèile yī fèn jīngměi de huàndēngpiàn, zài kèhù miànqián zuòle yī cì chénggōng de xiàngmù yǎnshì.", "translation": { "ru": "Он подготовил красивую презентацию и успешно представил проект клиенту.", "en": "He prepared a polished slideshow and gave a successful project presentation to the client." }, "difficulty": "hard" }] },
  { "chinese": "策略", "pinyin": "cèlüè", "translations": { "ru": "стратегия, тактика", "en": "strategy, tactic" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "我们需要一个新的营销策略。", "pinyin": "Wǒmen xūyào yī ge xīn de yíngxiāo cèlüè.", "translation": { "ru": "Нам нужна новая маркетинговая стратегия.", "en": "We need a new marketing strategy." }, "difficulty": "medium" }, { "chinese": "公司制定了差异化竞争策略，通过技术创新和优质服务来区别于竞争对手。", "pinyin": "Gōngsī zhìdìngle chāyìhuà jìngzhēng cèlüè, tōngguò jìshù chuàngxīn hé yōuzhì fúwù lái qūbié yú jìngzhēng duìshǒu.", "translation": { "ru": "Компания разработала стратегию дифференциации, отличаясь от конкурентов за счёт инноваций и качественного сервиса.", "en": "The company developed a differentiation strategy, distinguishing itself from competitors through innovation and quality service." }, "difficulty": "hard" }] },
  { "chinese": "计划", "pinyin": "jìhuà", "translations": { "ru": "план, планировать", "en": "plan, to plan" }, "difficulty": "easy", "hskLevel": 2, "tags": ["business", "general"], "examples": [{ "chinese": "你有什么计划？", "pinyin": "Nǐ yǒu shénme jìhuà?", "translation": { "ru": "Какие у тебя планы?", "en": "What are your plans?" }, "difficulty": "easy" }, { "chinese": "管理层正在制定明年的业务发展计划和资金使用方案。", "pinyin": "Guǎnlǐcéng zhèngzài zhìdìng míngnián de yèwù fāzhǎn jìhuà hé zījīn shǐyòng fāng'àn.", "translation": { "ru": "Руководство разрабатывает план развития бизнеса и схему распределения средств на следующий год.", "en": "Management is developing next year's business development plan and capital allocation scheme." }, "difficulty": "hard" }] },
  { "chinese": "目标", "pinyin": "mùbiāo", "translations": { "ru": "цель, задача", "en": "goal, target, objective" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "我们的目标是提高销售额。", "pinyin": "Wǒmen de mùbiāo shì tígāo xiāoshòu'é.", "translation": { "ru": "Наша цель — увеличить объём продаж.", "en": "Our goal is to increase sales." }, "difficulty": "easy" }, { "chinese": "公司设定了年收入突破十亿元的战略目标，各部门已开始分解任务。", "pinyin": "Gōngsī shèdìngle nián shōurù tūpò shí yì yuán de zhànlüè mùbiāo, gè bùmén yǐ kāishǐ fēnjiě rènwù.", "translation": { "ru": "Компания поставила стратегическую цель — превысить годовой доход в миллиард юаней, отделы уже приступили к разбивке задач.", "en": "The company set a strategic goal of exceeding one billion yuan in annual revenue, and departments have begun breaking down tasks." }, "difficulty": "hard" }] },
  { "chinese": "截止日期", "pinyin": "jiézhǐ rìqī", "translations": { "ru": "крайний срок, дедлайн", "en": "deadline" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "截止日期是下周五。", "pinyin": "Jiézhǐ rìqī shì xià zhōuwǔ.", "translation": { "ru": "Крайний срок — следующая пятница.", "en": "The deadline is next Friday." }, "difficulty": "easy" }, { "chinese": "由于项目进度严重滞后，团队不得不加班赶在截止日期前完成交付。", "pinyin": "Yóuyú xiàngmù jìndù yánzhòng zhìhòu, tuánduì bùdébù jiābān gǎn zài jiézhǐ rìqī qián wánchéng jiāofù.", "translation": { "ru": "Из-за серьёзного отставания графика команде пришлось работать сверхурочно, чтобы уложиться в дедлайн.", "en": "Due to the project being seriously behind schedule, the team had to work overtime to deliver before the deadline." }, "difficulty": "hard" }] },
  { "chinese": "日程", "pinyin": "rìchéng", "translations": { "ru": "расписание, график", "en": "schedule, agenda" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "你今天的日程安排是什么？", "pinyin": "Nǐ jīntiān de rìchéng ānpái shì shénme?", "translation": { "ru": "Какое у тебя расписание на сегодня?", "en": "What is your schedule for today?" }, "difficulty": "easy" }, { "chinese": "秘书帮总经理安排了一整天的日程，包括三个会议和两个客户拜访。", "pinyin": "Mìshū bāng zǒngjīnglǐ ānpáile yī zhěng tiān de rìchéng, bāokuò sān ge huìyì hé liǎng ge kèhù bàifǎng.", "translation": { "ru": "Секретарь составила генеральному директору расписание на весь день: три совещания и два визита к клиентам.", "en": "The secretary arranged a full day's schedule for the GM, including three meetings and two client visits." }, "difficulty": "hard" }] },
  { "chinese": "项目", "pinyin": "xiàngmù", "translations": { "ru": "проект", "en": "project" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这个项目很重要。", "pinyin": "Zhège xiàngmù hěn zhòngyào.", "translation": { "ru": "Этот проект очень важный.", "en": "This project is very important." }, "difficulty": "easy" }, { "chinese": "项目经理负责协调各部门资源，确保项目按时按质完成。", "pinyin": "Xiàngmù jīnglǐ fùzé xiétiáo gè bùmén zīyuán, quèbǎo xiàngmù ànshí àn zhì wánchéng.", "translation": { "ru": "Проектный менеджер отвечает за координацию ресурсов отделов и обеспечение своевременного и качественного выполнения проекта.", "en": "The project manager coordinates resources across departments to ensure timely and quality project completion." }, "difficulty": "hard" }] },
  { "chinese": "团队", "pinyin": "tuánduì", "translations": { "ru": "команда", "en": "team" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "我们的团队很棒。", "pinyin": "Wǒmen de tuánduì hěn bàng.", "translation": { "ru": "У нас отличная команда.", "en": "Our team is great." }, "difficulty": "easy" }, { "chinese": "一个高效的团队需要明确的分工、良好的沟通和共同的目标。", "pinyin": "Yī ge gāoxiào de tuánduì xūyào míngquè de fēngōng, liánghǎo de gōutōng hé gòngtóng de mùbiāo.", "translation": { "ru": "Эффективной команде нужны чёткое разделение обязанностей, хорошая коммуникация и общие цели.", "en": "An efficient team needs clear division of labor, good communication, and shared goals." }, "difficulty": "hard" }] },
  { "chinese": "部门", "pinyin": "bùmén", "translations": { "ru": "отдел, подразделение", "en": "department" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "你在哪个部门工作？", "pinyin": "Nǐ zài nǎge bùmén gōngzuò?", "translation": { "ru": "В каком отделе ты работаешь?", "en": "Which department do you work in?" }, "difficulty": "easy" }, { "chinese": "公司进行了组织架构调整，新增了数据分析部门和用户体验部门。", "pinyin": "Gōngsī jìnxíngle zǔzhī jiàgòu tiáozhěng, xīnzēngle shùjù fēnxī bùmén hé yònghù tǐyàn bùmén.", "translation": { "ru": "Компания провела реструктуризацию, создав отделы аналитики данных и пользовательского опыта.", "en": "The company restructured and added data analytics and user experience departments." }, "difficulty": "hard" }] },
  { "chinese": "分公司", "pinyin": "fēn gōngsī", "translations": { "ru": "филиал", "en": "branch company, subsidiary" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我们在上海有一家分公司。", "pinyin": "Wǒmen zài Shànghǎi yǒu yī jiā fēn gōngsī.", "translation": { "ru": "У нас есть филиал в Шанхае.", "en": "We have a branch company in Shanghai." }, "difficulty": "easy" }, { "chinese": "总部决定在东南亚设立分公司，以拓展海外市场。", "pinyin": "Zǒngbù juédìng zài dōngnányà shèlì fēn gōngsī, yǐ tuòzhǎn hǎiwài shìchǎng.", "translation": { "ru": "Штаб-квартира решила открыть филиал в Юго-Восточной Азии для расширения зарубежного рынка.", "en": "Headquarters decided to establish a branch in Southeast Asia to expand overseas markets." }, "difficulty": "hard" }] },
  { "chinese": "总部", "pinyin": "zǒngbù", "translations": { "ru": "штаб-квартира, головной офис", "en": "headquarters" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司总部在北京。", "pinyin": "Gōngsī zǒngbù zài Běijīng.", "translation": { "ru": "Штаб-квартира компании в Пекине.", "en": "The company's headquarters is in Beijing." }, "difficulty": "easy" }, { "chinese": "总部下发了新的绩效考核制度，要求所有分公司统一执行。", "pinyin": "Zǒngbù xiàfāle xīn de jìxiào kǎohé zhìdù, yāoqiú suǒyǒu fēn gōngsī tǒngyī zhíxíng.", "translation": { "ru": "Головной офис разослал новую систему оценки эффективности с требованием единого применения во всех филиалах.", "en": "Headquarters issued a new performance evaluation system, requiring all branches to implement it uniformly." }, "difficulty": "hard" }] },
  { "chinese": "分支", "pinyin": "fēnzhī", "translations": { "ru": "филиал, отделение", "en": "branch" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "银行在全国有很多分支。", "pinyin": "Yínháng zài quánguó yǒu hěn duō fēnzhī.", "translation": { "ru": "У банка много отделений по всей стране.", "en": "The bank has many branches across the country." }, "difficulty": "easy" }, { "chinese": "公司计划在三年内将分支机构数量从十家扩展到三十家。", "pinyin": "Gōngsī jìhuà zài sān nián nèi jiāng fēnzhī jīgòu shùliàng cóng shí jiā kuòzhǎn dào sānshí jiā.", "translation": { "ru": "Компания планирует увеличить количество филиалов с десяти до тридцати за три года.", "en": "The company plans to expand the number of branches from ten to thirty within three years." }, "difficulty": "hard" }] },
  { "chinese": "加盟", "pinyin": "jiāméng", "translations": { "ru": "франшиза, присоединиться", "en": "franchise, to join" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "他加盟了一家连锁品牌。", "pinyin": "Tā jiāméngle yī jiā liánsuǒ pǐnpái.", "translation": { "ru": "Он присоединился к сетевому бренду по франшизе.", "en": "He joined a franchise chain brand." }, "difficulty": "medium" }, { "chinese": "加盟商需要支付品牌使用费，并严格遵守总部的运营标准。", "pinyin": "Jiāméngshāng xūyào zhīfù pǐnpái shǐyòngfèi, bìng yángé zūnshǒu zǒngbù de yùnyíng biāozhǔn.", "translation": { "ru": "Франчайзи обязан платить роялти за использование бренда и строго соблюдать операционные стандарты головного офиса.", "en": "Franchisees need to pay brand fees and strictly follow headquarters' operational standards." }, "difficulty": "hard" }] },
  { "chinese": "创业", "pinyin": "chuàngyè", "translations": { "ru": "предпринимательство, начать бизнес", "en": "entrepreneurship, to start a business" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "很多年轻人想创业。", "pinyin": "Hěn duō niánqīngrén xiǎng chuàngyè.", "translation": { "ru": "Многие молодые люди хотят начать свой бизнес.", "en": "Many young people want to start a business." }, "difficulty": "easy" }, { "chinese": "创业初期资金紧张，他不得不身兼数职，既是老板又是销售。", "pinyin": "Chuàngyè chūqī zījīn jǐnzhāng, tā bùdébù shēn jiān shù zhí, jì shì lǎobǎn yòu shì xiāoshòu.", "translation": { "ru": "В начале предпринимательского пути средств было мало, ему приходилось совмещать несколько ролей — и руководителя, и продавца.", "en": "In the early days of the startup, funds were tight, and he had to wear multiple hats as both boss and salesperson." }, "difficulty": "hard" }] },
  { "chinese": "企业家", "pinyin": "qǐyèjiā", "translations": { "ru": "предприниматель", "en": "entrepreneur" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "他是一位成功的企业家。", "pinyin": "Tā shì yī wèi chénggōng de qǐyèjiā.", "translation": { "ru": "Он успешный предприниматель.", "en": "He is a successful entrepreneur." }, "difficulty": "easy" }, { "chinese": "这位企业家白手起家，用二十年时间把一个小作坊发展成了跨国集团。", "pinyin": "Zhè wèi qǐyèjiā báishǒuqǐjiā, yòng èrshí nián shíjiān bǎ yī ge xiǎo zuōfang fāzhǎn chéngle kuàguó jítuán.", "translation": { "ru": "Этот предприниматель начинал с нуля и за двадцать лет превратил маленькую мастерскую в транснациональную корпорацию.", "en": "This entrepreneur started from scratch and turned a small workshop into a multinational corporation in twenty years." }, "difficulty": "hard" }] },
  { "chinese": "创新", "pinyin": "chuàngxīn", "translations": { "ru": "инновация, новаторство", "en": "innovation" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "创新对企业发展很重要。", "pinyin": "Chuàngxīn duì qǐyè fāzhǎn hěn zhòngyào.", "translation": { "ru": "Инновации важны для развития предприятия.", "en": "Innovation is important for business development." }, "difficulty": "easy" }, { "chinese": "公司每年将营业收入的百分之八投入到技术创新和产品研发中。", "pinyin": "Gōngsī měi nián jiāng yíngyè shōurù de bǎifēn zhī bā tóurù dào jìshù chuàngxīn hé chǎnpǐn yánfā zhōng.", "translation": { "ru": "Компания ежегодно вкладывает 8% выручки в технологические инновации и разработку продуктов.", "en": "The company invests 8% of its annual revenue in technological innovation and product R&D." }, "difficulty": "hard" }] },
  { "chinese": "技术", "pinyin": "jìshù", "translations": { "ru": "технология, техника", "en": "technology, technique" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "这项技术很先进。", "pinyin": "Zhè xiàng jìshù hěn xiānjìn.", "translation": { "ru": "Эта технология очень передовая.", "en": "This technology is very advanced." }, "difficulty": "easy" }, { "chinese": "公司引进了国外最新的生产技术，大幅提高了产品的竞争力。", "pinyin": "Gōngsī yǐnjìnle guówài zuìxīn de shēngchǎn jìshù, dàfú tígāole chǎnpǐn de jìngzhēnglì.", "translation": { "ru": "Компания внедрила новейшие зарубежные производственные технологии, значительно повысив конкурентоспособность продукции.", "en": "The company introduced the latest foreign production technology, greatly improving product competitiveness." }, "difficulty": "hard" }] },
  { "chinese": "研发", "pinyin": "yánfā", "translations": { "ru": "исследования и разработки (НИОКР)", "en": "R&D, research and development" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司加大了研发投入。", "pinyin": "Gōngsī jiādàle yánfā tóurù.", "translation": { "ru": "Компания увеличила инвестиции в НИОКР.", "en": "The company increased R&D investment." }, "difficulty": "medium" }, { "chinese": "研发团队经过两年的努力，终于成功开发出了具有自主知识产权的核心技术。", "pinyin": "Yánfā tuánduì jīngguò liǎng nián de nǔlì, zhōngyú chénggōng kāifā chūle jùyǒu zìzhǔ zhīshì chǎnquán de héxīn jìshù.", "translation": { "ru": "После двух лет работы команда R&D наконец разработала ключевую технологию с собственными правами интеллектуальной собственности.", "en": "After two years of effort, the R&D team successfully developed core technology with independent intellectual property rights." }, "difficulty": "hard" }] },
  { "chinese": "专利", "pinyin": "zhuānlì", "translations": { "ru": "патент", "en": "patent" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "这项技术已经申请了专利。", "pinyin": "Zhè xiàng jìshù yǐjīng shēnqǐngle zhuānlì.", "translation": { "ru": "На эту технологию уже подана заявка на патент.", "en": "A patent has been applied for this technology." }, "difficulty": "medium" }, { "chinese": "公司目前拥有一百多项发明专利，在行业中处于领先地位。", "pinyin": "Gōngsī mùqián yōngyǒu yībǎi duō xiàng fāmíng zhuānlì, zài hángyè zhōng chǔyú lǐngxiān dìwèi.", "translation": { "ru": "Компания владеет более чем ста патентами на изобретения и занимает лидирующие позиции в отрасли.", "en": "The company currently holds over 100 invention patents and is a leader in the industry." }, "difficulty": "hard" }] },
  { "chinese": "版权", "pinyin": "bǎnquán", "translations": { "ru": "авторское право", "en": "copyright" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "这本书的版权归作者所有。", "pinyin": "Zhè běn shū de bǎnquán guī zuòzhě suǒyǒu.", "translation": { "ru": "Авторские права на эту книгу принадлежат автору.", "en": "The copyright of this book belongs to the author." }, "difficulty": "medium" }, { "chinese": "未经版权持有人授权，任何人不得复制、传播或商业使用该作品。", "pinyin": "Wèi jīng bǎnquán chíyǒurén shòuquán, rènhé rén bùdé fùzhì, chuánbò huò shāngyè shǐyòng gāi zuòpǐn.", "translation": { "ru": "Без разрешения правообладателя никто не вправе копировать, распространять или использовать произведение в коммерческих целях.", "en": "Without authorization from the copyright holder, no one may copy, distribute, or commercially use the work." }, "difficulty": "hard" }] },
  { "chinese": "商标权", "pinyin": "shāngbiāoquán", "translations": { "ru": "право на товарный знак", "en": "trademark right" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "商标权受法律保护。", "pinyin": "Shāngbiāoquán shòu fǎlǜ bǎohù.", "translation": { "ru": "Право на товарный знак защищено законом.", "en": "Trademark rights are protected by law." }, "difficulty": "medium" }, { "chinese": "企业应积极维护自身的商标权，对侵权行为及时采取法律措施。", "pinyin": "Qǐyè yīng jījí wéihù zìshēn de shāngbiāoquán, duì qīnquán xíngwéi jíshí cǎiqǔ fǎlǜ cuòshī.", "translation": { "ru": "Предприятия должны активно защищать свои права на товарный знак и своевременно принимать правовые меры против нарушений.", "en": "Enterprises should actively protect their trademark rights and promptly take legal action against infringement." }, "difficulty": "hard" }] },
  { "chinese": "合并", "pinyin": "hébìng", "translations": { "ru": "слияние, объединение", "en": "merger, to merge" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "两家公司决定合并。", "pinyin": "Liǎng jiā gōngsī juédìng hébìng.", "translation": { "ru": "Две компании решили объединиться.", "en": "The two companies decided to merge." }, "difficulty": "medium" }, { "chinese": "合并后的新公司将成为该行业最大的企业，市场份额超过百分之三十。", "pinyin": "Hébìng hòu de xīn gōngsī jiāng chéngwéi gāi hángyè zuìdà de qǐyè, shìchǎng fèn'é chāoguò bǎifēn zhī sānshí.", "translation": { "ru": "Объединённая компания станет крупнейшей в отрасли с рыночной долей более 30%.", "en": "The merged company will become the largest in the industry with a market share exceeding 30%." }, "difficulty": "hard" }] },
  { "chinese": "收购", "pinyin": "shōugòu", "translations": { "ru": "поглощение, приобретение", "en": "acquisition, to acquire" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "大公司收购了一家小公司。", "pinyin": "Dà gōngsī shōugòule yī jiā xiǎo gōngsī.", "translation": { "ru": "Крупная компания поглотила маленькую.", "en": "The big company acquired a small company." }, "difficulty": "medium" }, { "chinese": "这次跨国收购涉及金额高达五十亿美元，是今年最大的一笔并购交易。", "pinyin": "Zhè cì kuàguó shōugòu shèjí jīn'é gāodá wǔshí yì měiyuán, shì jīnnián zuìdà de yī bǐ bìnggòu jiāoyì.", "translation": { "ru": "Эта трансграничная сделка по приобретению стоимостью до 5 миллиардов долларов — крупнейшая сделка M&A в этом году.", "en": "This cross-border acquisition involves up to 5 billion dollars and is the largest M&A deal this year." }, "difficulty": "hard" }] },
  { "chinese": "破产", "pinyin": "pòchǎn", "translations": { "ru": "банкротство", "en": "bankruptcy" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "那家公司破产了。", "pinyin": "Nà jiā gōngsī pòchǎn le.", "translation": { "ru": "Та компания обанкротилась.", "en": "That company went bankrupt." }, "difficulty": "easy" }, { "chinese": "由于长期经营不善和债务累积，该企业最终不得不申请破产保护。", "pinyin": "Yóuyú chángqī jīngyíng bùshàn hé zhàiwù lěijī, gāi qǐyè zuìzhōng bùdébù shēnqǐng pòchǎn bǎohù.", "translation": { "ru": "Из-за длительного плохого управления и накопления долгов предприятие в итоге вынуждено было подать заявление о банкротстве.", "en": "Due to long-term mismanagement and debt accumulation, the enterprise ultimately had to file for bankruptcy protection." }, "difficulty": "hard" }] },
  { "chinese": "重组", "pinyin": "chóngzǔ", "translations": { "ru": "реструктуризация, реорганизация", "en": "restructuring, reorganization" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司正在进行重组。", "pinyin": "Gōngsī zhèngzài jìnxíng chóngzǔ.", "translation": { "ru": "Компания проходит реструктуризацию.", "en": "The company is undergoing restructuring." }, "difficulty": "medium" }, { "chinese": "债务重组方案获得了债权人的同意，公司有望在半年内恢复正常运营。", "pinyin": "Zhàiwù chóngzǔ fāng'àn huòdéle zhàiquánrén de tóngyì, gōngsī yǒuwàng zài bànnián nèi huīfù zhèngcháng yùnyíng.", "translation": { "ru": "План реструктуризации долга получил одобрение кредиторов, и компания может возобновить нормальную деятельность в течение полугода.", "en": "The debt restructuring plan was approved by creditors, and the company is expected to resume normal operations within six months." }, "difficulty": "hard" }] },
  { "chinese": "咨询", "pinyin": "zīxún", "translations": { "ru": "консультация, консалтинг", "en": "consultation, consulting" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我想咨询一下贷款的事。", "pinyin": "Wǒ xiǎng zīxún yīxià dàikuǎn de shì.", "translation": { "ru": "Я хотел бы проконсультироваться по поводу кредита.", "en": "I'd like to inquire about a loan." }, "difficulty": "easy" }, { "chinese": "公司聘请了国际知名的管理咨询公司来优化内部流程和组织架构。", "pinyin": "Gōngsī pìnqǐngle guójì zhīmíng de guǎnlǐ zīxún gōngsī lái yōuhuà nèibù liúchéng hé zǔzhī jiàgòu.", "translation": { "ru": "Компания наняла всемирно известную управленческую консалтинговую фирму для оптимизации внутренних процессов и оргструктуры.", "en": "The company hired an internationally renowned management consulting firm to optimize internal processes and organizational structure." }, "difficulty": "hard" }] },
  { "chinese": "外包", "pinyin": "wàibāo", "translations": { "ru": "аутсорсинг", "en": "outsourcing" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "这个项目外包给了别的公司。", "pinyin": "Zhège xiàngmù wàibāo gěile bié de gōngsī.", "translation": { "ru": "Этот проект отдали на аутсорсинг другой компании.", "en": "This project was outsourced to another company." }, "difficulty": "medium" }, { "chinese": "为了降低运营成本，公司决定将客服和数据处理业务外包给专业服务商。", "pinyin": "Wèile jiàngdī yùnyíng chéngběn, gōngsī juédìng jiāng kèfú hé shùjù chǔlǐ yèwù wàibāo gěi zhuānyè fúwùshāng.", "translation": { "ru": "Для снижения операционных расходов компания решила передать клиентский сервис и обработку данных на аутсорсинг.", "en": "To reduce operating costs, the company decided to outsource customer service and data processing to professional service providers." }, "difficulty": "hard" }] },
  { "chinese": "简历", "pinyin": "jiǎnlì", "translations": { "ru": "резюме", "en": "resume, CV" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "请把你的简历发给我。", "pinyin": "Qǐng bǎ nǐ de jiǎnlì fā gěi wǒ.", "translation": { "ru": "Пришлите мне, пожалуйста, ваше резюме.", "en": "Please send me your resume." }, "difficulty": "easy" }, { "chinese": "他精心修改了简历，突出了自己在项目管理和团队领导方面的经验。", "pinyin": "Tā jīngxīn xiūgǎile jiǎnlì, tūchūle zìjǐ zài xiàngmù guǎnlǐ hé tuánduì lǐngdǎo fāngmiàn de jīngyàn.", "translation": { "ru": "Он тщательно переработал резюме, подчеркнув опыт в управлении проектами и руководстве командой.", "en": "He carefully revised his resume, highlighting his experience in project management and team leadership." }, "difficulty": "hard" }] },
  { "chinese": "面试", "pinyin": "miànshì", "translations": { "ru": "собеседование", "en": "interview" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "我明天有一个面试。", "pinyin": "Wǒ míngtiān yǒu yī ge miànshì.", "translation": { "ru": "Завтра у меня собеседование.", "en": "I have an interview tomorrow." }, "difficulty": "easy" }, { "chinese": "面试官问了很多关于团队合作和解决问题能力的行为面试题。", "pinyin": "Miànshìguān wènle hěn duō guānyú tuánduì hézuò hé jiějué wèntí nénglì de xíngwéi miànshì tí.", "translation": { "ru": "Интервьюер задал много поведенческих вопросов о командной работе и умении решать проблемы.", "en": "The interviewer asked many behavioral questions about teamwork and problem-solving abilities." }, "difficulty": "hard" }] },
  { "chinese": "培训", "pinyin": "péixùn", "translations": { "ru": "обучение, тренинг", "en": "training" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "新员工需要参加培训。", "pinyin": "Xīn yuángōng xūyào cānjiā péixùn.", "translation": { "ru": "Новые сотрудники должны пройти обучение.", "en": "New employees need to attend training." }, "difficulty": "easy" }, { "chinese": "公司每季度组织一次专业技能培训，帮助员工不断提升业务水平。", "pinyin": "Gōngsī měi jìdù zǔzhī yī cì zhuānyè jìnéng péixùn, bāngzhù yuángōng bùduàn tíshēng yèwù shuǐpíng.", "translation": { "ru": "Компания ежеквартально проводит тренинги по профессиональным навыкам для повышения квалификации сотрудников.", "en": "The company organizes professional skills training every quarter to help employees continuously improve." }, "difficulty": "hard" }] },
  { "chinese": "晋升", "pinyin": "jìnshēng", "translations": { "ru": "повышение (в должности)", "en": "promotion" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "他最近晋升为经理了。", "pinyin": "Tā zuìjìn jìnshēng wéi jīnglǐ le.", "translation": { "ru": "Его недавно повысили до менеджера.", "en": "He was recently promoted to manager." }, "difficulty": "easy" }, { "chinese": "公司实行透明的晋升机制，员工的晋升取决于绩效考核结果和能力评估。", "pinyin": "Gōngsī shíxíng tòumíng de jìnshēng jīzhì, yuángōng de jìnshēng qǔjué yú jìxiào kǎohé jiéguǒ hé nénglì pínggū.", "translation": { "ru": "Компания применяет прозрачный механизм продвижения: повышение зависит от результатов аттестации и оценки компетенций.", "en": "The company implements a transparent promotion mechanism based on performance reviews and competency assessments." }, "difficulty": "hard" }] },
  { "chinese": "辞职", "pinyin": "cízhí", "translations": { "ru": "увольнение (по собственному желанию)", "en": "to resign" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "他决定辞职了。", "pinyin": "Tā juédìng cízhí le.", "translation": { "ru": "Он решил уволиться.", "en": "He decided to resign." }, "difficulty": "easy" }, { "chinese": "她向公司提交了辞职申请，并表示希望在一个月后正式离职。", "pinyin": "Tā xiàng gōngsī tíjiāole cízhí shēnqǐng, bìng biǎoshì xīwàng zài yī ge yuè hòu zhèngshì lízhí.", "translation": { "ru": "Она подала заявление об увольнении и выразила надежду официально уйти через месяц.", "en": "She submitted her resignation and expressed hope to officially leave in one month." }, "difficulty": "hard" }] },
  { "chinese": "招聘", "pinyin": "zhāopìn", "translations": { "ru": "набор персонала, рекрутинг", "en": "recruitment, to recruit" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "公司正在招聘新员工。", "pinyin": "Gōngsī zhèngzài zhāopìn xīn yuángōng.", "translation": { "ru": "Компания набирает новых сотрудников.", "en": "The company is recruiting new employees." }, "difficulty": "easy" }, { "chinese": "人事部通过线上招聘平台和校园宣讲会等多种渠道吸引优秀人才。", "pinyin": "Rénshì bù tōngguò xiànshàng zhāopìn píngtái hé xiàoyuán xuānjiǎnghuì děng duō zhǒng qúdào xīyǐn yōuxiù réncái.", "translation": { "ru": "HR-отдел привлекает талантливых специалистов через онлайн-платформы и презентации в вузах.", "en": "The HR department attracts talent through online recruitment platforms and campus presentations." }, "difficulty": "hard" }] },
  { "chinese": "福利", "pinyin": "fúlì", "translations": { "ru": "социальные льготы, бонусы", "en": "benefits, welfare" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "这家公司的员工福利很好。", "pinyin": "Zhè jiā gōngsī de yuángōng fúlì hěn hǎo.", "translation": { "ru": "В этой компании хорошие социальные льготы для сотрудников.", "en": "This company has good employee benefits." }, "difficulty": "easy" }, { "chinese": "除了基本工资外，公司还提供带薪年假、住房补贴和子女教育基金等福利。", "pinyin": "Chúle jīběn gōngzī wài, gōngsī hái tígōng dàixīn niánjià, zhùfáng bǔtiē hé zǐnǚ jiàoyù jījīn děng fúlì.", "translation": { "ru": "Помимо базовой зарплаты, компания предоставляет оплачиваемый отпуск, субсидии на жильё и фонд на образование детей.", "en": "Besides base salary, the company provides paid annual leave, housing subsidies, and children's education funds." }, "difficulty": "hard" }] },
  { "chinese": "社保", "pinyin": "shèbǎo", "translations": { "ru": "социальное страхование", "en": "social insurance" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "公司帮员工交社保。", "pinyin": "Gōngsī bāng yuángōng jiāo shèbǎo.", "translation": { "ru": "Компания платит за социальное страхование сотрудников.", "en": "The company pays social insurance for employees." }, "difficulty": "easy" }, { "chinese": "根据劳动法规定，用人单位必须为员工缴纳养老、医疗、失业等社会保险。", "pinyin": "Gēnjù láodòngfǎ guīdìng, yòngrén dānwèi bìxū wèi yuángōng jiǎonà yǎnglǎo, yīliáo, shīyè děng shèhuì bǎoxiǎn.", "translation": { "ru": "Согласно трудовому законодательству, работодатель обязан платить пенсионное, медицинское и страхование по безработице за сотрудников.", "en": "According to labor law, employers must pay pension, medical, and unemployment insurance for employees." }, "difficulty": "hard" }] },
  { "chinese": "加班", "pinyin": "jiābān", "translations": { "ru": "сверхурочная работа", "en": "overtime" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "我今天要加班。", "pinyin": "Wǒ jīntiān yào jiābān.", "translation": { "ru": "Мне сегодня нужно работать сверхурочно.", "en": "I need to work overtime today." }, "difficulty": "easy" }, { "chinese": "公司规定加班必须提前申请，并按照国家法律支付加班费。", "pinyin": "Gōngsī guīdìng jiābān bìxū tíqián shēnqǐng, bìng ànzhào guójiā fǎlǜ zhīfù jiābānfèi.", "translation": { "ru": "По правилам компании, сверхурочная работа требует предварительного согласования, а оплата — по законодательству.", "en": "Company policy requires advance approval for overtime, with overtime pay according to national law." }, "difficulty": "hard" }] },
  { "chinese": "出差", "pinyin": "chūchāi", "translations": { "ru": "командировка", "en": "business trip" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "他下周要去北京出差。", "pinyin": "Tā xià zhōu yào qù Běijīng chūchāi.", "translation": { "ru": "На следующей неделе он едет в командировку в Пекин.", "en": "He is going on a business trip to Beijing next week." }, "difficulty": "easy" }, { "chinese": "出差期间的交通、住宿和餐饮费用可以凭发票向公司报销。", "pinyin": "Chūchāi qījiān de jiāotōng, zhùsù hé cānyǐn fèiyòng kěyǐ píng fāpiào xiàng gōngsī bàoxiāo.", "translation": { "ru": "Расходы на транспорт, проживание и питание во время командировки можно возместить по чекам.", "en": "Travel, accommodation, and meal expenses during business trips can be reimbursed with receipts." }, "difficulty": "hard" }] },
  { "chinese": "电话", "pinyin": "diànhuà", "translations": { "ru": "телефон", "en": "telephone, phone call" }, "difficulty": "easy", "hskLevel": 1, "tags": ["business", "general"], "examples": [{ "chinese": "请给我打电话。", "pinyin": "Qǐng gěi wǒ dǎ diànhuà.", "translation": { "ru": "Пожалуйста, позвоните мне.", "en": "Please give me a call." }, "difficulty": "easy" }, { "chinese": "客服部门每天处理大约两百个客户电话，解答各类产品和服务的问题。", "pinyin": "Kèfú bùmén měitiān chǔlǐ dàyuē liǎngbǎi ge kèhù diànhuà, jiědá gè lèi chǎnpǐn hé fúwù de wèntí.", "translation": { "ru": "Отдел обслуживания клиентов ежедневно обрабатывает около 200 звонков, отвечая на вопросы о продуктах и услугах.", "en": "The customer service department handles about 200 customer calls daily, answering various product and service questions." }, "difficulty": "hard" }] },
  { "chinese": "邮件", "pinyin": "yóujiàn", "translations": { "ru": "электронная почта, письмо", "en": "email, mail" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "我给你发了一封邮件。", "pinyin": "Wǒ gěi nǐ fāle yī fēng yóujiàn.", "translation": { "ru": "Я отправил тебе письмо.", "en": "I sent you an email." }, "difficulty": "easy" }, { "chinese": "在商务邮件中，应使用正式语气，并注意格式规范和礼貌用语。", "pinyin": "Zài shāngwù yóujiàn zhōng, yīng shǐyòng zhèngshì yǔqì, bìng zhùyì géshì guīfàn hé lǐmào yòngyǔ.", "translation": { "ru": "В деловых письмах следует использовать официальный тон, соблюдать правила оформления и вежливые формулировки.", "en": "In business emails, you should use a formal tone and pay attention to proper formatting and polite language." }, "difficulty": "hard" }] },
  { "chinese": "文件", "pinyin": "wénjiàn", "translations": { "ru": "документ, файл", "en": "document, file" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "请把文件发给我。", "pinyin": "Qǐng bǎ wénjiàn fā gěi wǒ.", "translation": { "ru": "Пришлите мне, пожалуйста, документ.", "en": "Please send me the document." }, "difficulty": "easy" }, { "chinese": "所有机密文件必须存放在保险柜中，未经授权不得复印或外传。", "pinyin": "Suǒyǒu jīmì wénjiàn bìxū cúnfàng zài bǎoxiǎnguì zhōng, wèi jīng shòuquán bùdé fùyìn huò wàichuán.", "translation": { "ru": "Все конфиденциальные документы должны храниться в сейфе и не подлежат копированию или распространению без разрешения.", "en": "All confidential documents must be stored in a safe and cannot be copied or shared without authorization." }, "difficulty": "hard" }] },
  { "chinese": "签字", "pinyin": "qiānzì", "translations": { "ru": "подпись, подписать", "en": "to sign, signature" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "请在这里签字。", "pinyin": "Qǐng zài zhèlǐ qiānzì.", "translation": { "ru": "Пожалуйста, подпишите здесь.", "en": "Please sign here." }, "difficulty": "easy" }, { "chinese": "合同经双方法人代表签字并加盖公章后正式生效。", "pinyin": "Hétong jīng shuāngfāng fǎrén dàibiǎo qiānzì bìng jiāgài gōngzhāng hòu zhèngshì shēngxiào.", "translation": { "ru": "Договор вступает в силу после подписания уполномоченными представителями обеих сторон и заверения печатями.", "en": "The contract officially takes effect after being signed by both parties' legal representatives and stamped with official seals." }, "difficulty": "hard" }] },
  { "chinese": "盖章", "pinyin": "gàizhāng", "translations": { "ru": "ставить печать", "en": "to stamp, to seal" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "这份文件需要盖章。", "pinyin": "Zhè fèn wénjiàn xūyào gàizhāng.", "translation": { "ru": "На этот документ нужно поставить печать.", "en": "This document needs to be stamped." }, "difficulty": "easy" }, { "chinese": "在中国，合同和正式文件通常需要加盖公司的公章才具有法律效力。", "pinyin": "Zài Zhōngguó, hétong hé zhèngshì wénjiàn tōngcháng xūyào jiāgài gōngsī de gōngzhāng cái jùyǒu fǎlǜ xiàolì.", "translation": { "ru": "В Китае контракты и официальные документы обычно требуют печати компании для юридической силы.", "en": "In China, contracts and official documents typically need the company's official seal to have legal validity." }, "difficulty": "hard" }] },
  { "chinese": "证书", "pinyin": "zhèngshū", "translations": { "ru": "сертификат, свидетельство", "en": "certificate" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "他获得了一个专业证书。", "pinyin": "Tā huòdéle yī ge zhuānyè zhèngshū.", "translation": { "ru": "Он получил профессиональный сертификат.", "en": "He obtained a professional certificate." }, "difficulty": "easy" }, { "chinese": "取得国际质量管理体系认证证书有助于提升企业在海外市场的公信力。", "pinyin": "Qǔdé guójì zhìliàng guǎnlǐ tǐxì rènzhèng zhèngshū yǒuzhùyú tíshēng qǐyè zài hǎiwài shìchǎng de gōngxìnlì.", "translation": { "ru": "Получение сертификата международной системы менеджмента качества помогает повысить доверие к предприятию на зарубежных рынках.", "en": "Obtaining an international quality management system certification helps enhance the enterprise's credibility in overseas markets." }, "difficulty": "hard" }] },
  { "chinese": "资质", "pinyin": "zīzhì", "translations": { "ru": "квалификация, лицензия", "en": "qualification, credentials" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "这家公司有资质吗？", "pinyin": "Zhè jiā gōngsī yǒu zīzhì ma?", "translation": { "ru": "У этой компании есть лицензия?", "en": "Does this company have the qualifications?" }, "difficulty": "easy" }, { "chinese": "投标企业必须提供营业执照、税务登记证和相关行业资质证明。", "pinyin": "Tóubiāo qǐyè bìxū tígōng yíngyè zhízhào, shuìwù dēngjìzhèng hé xiāngguān hángyè zīzhì zhèngmíng.", "translation": { "ru": "Участвующие в тендере предприятия обязаны предоставить лицензию, налоговое свидетельство и подтверждение отраслевой квалификации.", "en": "Bidding enterprises must provide a business license, tax registration, and relevant industry qualification certificates." }, "difficulty": "hard" }] },
  { "chinese": "信用", "pinyin": "xìnyòng", "translations": { "ru": "кредит, доверие, репутация", "en": "credit, credibility" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "信用很重要。", "pinyin": "Xìnyòng hěn zhòngyào.", "translation": { "ru": "Кредитная репутация очень важна.", "en": "Credit is very important." }, "difficulty": "easy" }, { "chinese": "银行根据企业的信用评级来决定贷款额度和利率水平。", "pinyin": "Yínháng gēnjù qǐyè de xìnyòng píngjí lái juédìng dàikuǎn édù hé lìlǜ shuǐpíng.", "translation": { "ru": "Банк определяет кредитный лимит и процентную ставку на основе кредитного рейтинга предприятия.", "en": "Banks determine loan limits and interest rates based on the enterprise's credit rating." }, "difficulty": "hard" }] },
  { "chinese": "债务", "pinyin": "zhàiwù", "translations": { "ru": "долг, задолженность", "en": "debt" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司有很多债务。", "pinyin": "Gōngsī yǒu hěn duō zhàiwù.", "translation": { "ru": "У компании много долгов.", "en": "The company has a lot of debt." }, "difficulty": "easy" }, { "chinese": "企业通过出售非核心资产来偿还累积的债务，逐步改善财务状况。", "pinyin": "Qǐyè tōngguò chūshòu fēi héxīn zīchǎn lái chánghuán lěijī de zhàiwù, zhúbù gǎishàn cáiwù zhuàngkuàng.", "translation": { "ru": "Предприятие погашает накопленные долги за счёт продажи непрофильных активов, постепенно улучшая финансовое положение.", "en": "The enterprise repays accumulated debts by selling non-core assets, gradually improving its financial situation." }, "difficulty": "hard" }] },
  { "chinese": "融资", "pinyin": "róngzī", "translations": { "ru": "финансирование, привлечение капитала", "en": "financing, fundraising" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司正在进行融资。", "pinyin": "Gōngsī zhèngzài jìnxíng róngzī.", "translation": { "ru": "Компания привлекает финансирование.", "en": "The company is raising funds." }, "difficulty": "medium" }, { "chinese": "初创企业完成了A轮融资，获得了两千万美元的投资。", "pinyin": "Chūchuàng qǐyè wánchéngle A lún róngzī, huòdéle liǎngqiān wàn měiyuán de tóuzī.", "translation": { "ru": "Стартап завершил раунд A финансирования, получив 20 миллионов долларов инвестиций.", "en": "The startup completed Series A financing, securing 20 million dollars in investment." }, "difficulty": "hard" }] },
  { "chinese": "股票", "pinyin": "gǔpiào", "translations": { "ru": "акция", "en": "stock, share" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "他买了一些股票。", "pinyin": "Tā mǎile yīxiē gǔpiào.", "translation": { "ru": "Он купил несколько акций.", "en": "He bought some stocks." }, "difficulty": "easy" }, { "chinese": "受财报利好消息影响，该公司的股票价格在一周内上涨了百分之十五。", "pinyin": "Shòu cáibào lìhǎo xiāoxī yǐngxiǎng, gāi gōngsī de gǔpiào jiàgé zài yī zhōu nèi shàngzhǎngle bǎifēn zhī shíwǔ.", "translation": { "ru": "Благодаря позитивному финансовому отчёту акции компании выросли на 15% за неделю.", "en": "Driven by positive earnings reports, the company's stock price rose 15% within a week." }, "difficulty": "hard" }] },
  { "chinese": "股东", "pinyin": "gǔdōng", "translations": { "ru": "акционер", "en": "shareholder" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "股东大会下周召开。", "pinyin": "Gǔdōng dàhuì xià zhōu zhàokāi.", "translation": { "ru": "Собрание акционеров состоится на следующей неделе.", "en": "The shareholders' meeting will be held next week." }, "difficulty": "medium" }, { "chinese": "大股东提议将公司利润的百分之二十用于分红，百分之八十用于再投资。", "pinyin": "Dà gǔdōng tíyì jiāng gōngsī lìrùn de bǎifēn zhī èrshí yòngyú fēnhóng, bǎifēn zhī bāshí yòngyú zài tóuzī.", "translation": { "ru": "Крупный акционер предложил направить 20% прибыли на дивиденды и 80% на реинвестирование.", "en": "The major shareholder proposed using 20% of profits for dividends and 80% for reinvestment." }, "difficulty": "hard" }] },
  { "chinese": "分红", "pinyin": "fēnhóng", "translations": { "ru": "дивиденды", "en": "dividend, profit sharing" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "今年的分红比去年多。", "pinyin": "Jīnnián de fēnhóng bǐ qùnián duō.", "translation": { "ru": "Дивиденды в этом году больше, чем в прошлом.", "en": "This year's dividends are higher than last year's." }, "difficulty": "easy" }, { "chinese": "公司连续五年保持稳定分红，深受长期投资者的青睐。", "pinyin": "Gōngsī liánxù wǔ nián bǎochí wěndìng fēnhóng, shēn shòu chángqī tóuzīzhě de qīnglài.", "translation": { "ru": "Компания пять лет подряд стабильно выплачивает дивиденды, что привлекает долгосрочных инвесторов.", "en": "The company has maintained stable dividends for five consecutive years, attracting long-term investors." }, "difficulty": "hard" }] },
  { "chinese": "银行卡", "pinyin": "yínhángkǎ", "translations": { "ru": "банковская карта", "en": "bank card" }, "difficulty": "easy", "hskLevel": 2, "tags": ["business", "general"], "examples": [{ "chinese": "可以用银行卡付款吗？", "pinyin": "Kěyǐ yòng yínhángkǎ fùkuǎn ma?", "translation": { "ru": "Можно оплатить банковской картой?", "en": "Can I pay with a bank card?" }, "difficulty": "easy" }, { "chinese": "公司为每位新员工办理了工资银行卡，用于每月工资的自动发放。", "pinyin": "Gōngsī wèi měi wèi xīn yuángōng bànlǐle gōngzī yínhángkǎ, yòngyú měi yuè gōngzī de zìdòng fāfàng.", "translation": { "ru": "Компания оформила зарплатные карты для всех новых сотрудников для автоматического перечисления зарплаты.", "en": "The company arranged salary bank cards for each new employee for automatic monthly salary payments." }, "difficulty": "medium" }] },
  { "chinese": "现金", "pinyin": "xiànjīn", "translations": { "ru": "наличные деньги", "en": "cash" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "你带现金了吗？", "pinyin": "Nǐ dài xiànjīn le ma?", "translation": { "ru": "У тебя есть наличные?", "en": "Do you have cash?" }, "difficulty": "easy" }, { "chinese": "随着移动支付的普及，越来越少的人使用现金进行日常交易。", "pinyin": "Suízhe yídòng zhīfù de pǔjí, yuèláiyuè shǎo de rén shǐyòng xiànjīn jìnxíng rìcháng jiāoyì.", "translation": { "ru": "С распространением мобильных платежей всё меньше людей используют наличные для повседневных расчётов.", "en": "With the spread of mobile payments, fewer and fewer people use cash for daily transactions." }, "difficulty": "hard" }] },
  { "chinese": "转账", "pinyin": "zhuǎnzhàng", "translations": { "ru": "перевод (денежный)", "en": "bank transfer" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "我给你转账了。", "pinyin": "Wǒ gěi nǐ zhuǎnzhàng le.", "translation": { "ru": "Я перевёл тебе деньги.", "en": "I transferred the money to you." }, "difficulty": "easy" }, { "chinese": "跨行转账通常需要一到两个工作日才能到账，而同行转账则是实时到账。", "pinyin": "Kuà háng zhuǎnzhàng tōngcháng xūyào yī dào liǎng ge gōngzuòrì cáinéng dàozhàng, ér tóng háng zhuǎnzhàng zé shì shíshí dàozhàng.", "translation": { "ru": "Межбанковский перевод обычно занимает 1–2 рабочих дня, а внутрибанковский зачисляется мгновенно.", "en": "Cross-bank transfers usually take one to two business days, while same-bank transfers are instant." }, "difficulty": "hard" }] },
  { "chinese": "汇率", "pinyin": "huìlǜ", "translations": { "ru": "обменный курс", "en": "exchange rate" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "今天的汇率是多少？", "pinyin": "Jīntiān de huìlǜ shì duōshǎo?", "translation": { "ru": "Какой сегодня обменный курс?", "en": "What is today's exchange rate?" }, "difficulty": "easy" }, { "chinese": "汇率波动对出口企业的利润影响很大，需要通过金融工具来规避风险。", "pinyin": "Huìlǜ bōdòng duì chūkǒu qǐyè de lìrùn yǐngxiǎng hěn dà, xūyào tōngguò jīnróng gōngjù lái guībì fēngxiǎn.", "translation": { "ru": "Колебания обменного курса сильно влияют на прибыль экспортных предприятий, и нужно хеджировать риски с помощью финансовых инструментов.", "en": "Exchange rate fluctuations greatly affect export companies' profits and require financial instruments to hedge risks." }, "difficulty": "hard" }] },
  { "chinese": "利率", "pinyin": "lìlǜ", "translations": { "ru": "процентная ставка", "en": "interest rate" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "银行的利率是多少？", "pinyin": "Yínháng de lìlǜ shì duōshǎo?", "translation": { "ru": "Какая процентная ставка в банке?", "en": "What is the bank's interest rate?" }, "difficulty": "easy" }, { "chinese": "央行下调了基准利率，以刺激经济增长和企业投资。", "pinyin": "Yāngháng xiàtiáole jīzhǔn lìlǜ, yǐ cìjī jīngjì zēngzhǎng hé qǐyè tóuzī.", "translation": { "ru": "Центральный банк снизил базовую ставку для стимулирования экономического роста и инвестиций.", "en": "The central bank lowered the benchmark interest rate to stimulate economic growth and business investment." }, "difficulty": "hard" }] },
  { "chinese": "报价", "pinyin": "bàojià", "translations": { "ru": "ценовое предложение, котировка", "en": "quotation, to quote a price" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "请给我一个报价。", "pinyin": "Qǐng gěi wǒ yī ge bàojià.", "translation": { "ru": "Дайте мне ценовое предложение.", "en": "Please give me a quotation." }, "difficulty": "easy" }, { "chinese": "供应商的报价比预期高出百分之十，我们需要重新谈判或寻找替代方案。", "pinyin": "Gōngyìngshāng de bàojià bǐ yùqī gāochū bǎifēn zhī shí, wǒmen xūyào chóngxīn tánpàn huò xúnzhǎo tìdài fāng'àn.", "translation": { "ru": "Предложение поставщика на 10% выше ожидаемого, нужно либо пересмотреть условия, либо найти альтернативу.", "en": "The supplier's quotation is 10% higher than expected; we need to renegotiate or find alternatives." }, "difficulty": "hard" }] },
  { "chinese": "竞标", "pinyin": "jìngbiāo", "translations": { "ru": "участие в тендере", "en": "competitive bidding" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "我们公司参加了竞标。", "pinyin": "Wǒmen gōngsī cānjiāle jìngbiāo.", "translation": { "ru": "Наша компания участвовала в тендере.", "en": "Our company participated in the bidding." }, "difficulty": "medium" }, { "chinese": "五家企业参与了这个政府工程项目的竞标，最终结果将在下月公布。", "pinyin": "Wǔ jiā qǐyè cānyùle zhège zhèngfǔ gōngchéng xiàngmù de jìngbiāo, zuìzhōng jiéguǒ jiāng zài xià yuè gōngbù.", "translation": { "ru": "Пять компаний участвовали в тендере на государственный строительный проект, результаты объявят в следующем месяце.", "en": "Five companies participated in bidding for this government construction project; final results will be announced next month." }, "difficulty": "hard" }] },
  { "chinese": "中标", "pinyin": "zhòngbiāo", "translations": { "ru": "выиграть тендер", "en": "to win a bid" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "我们中标了！", "pinyin": "Wǒmen zhòngbiāo le!", "translation": { "ru": "Мы выиграли тендер!", "en": "We won the bid!" }, "difficulty": "easy" }, { "chinese": "公司凭借技术优势和合理的报价成功中标了这个价值五千万的工程项目。", "pinyin": "Gōngsī píngjiè jìshù yōushì hé hélǐ de bàojià chénggōng zhòngbiāole zhège jiàzhí wǔqiān wàn de gōngchéng xiàngmù.", "translation": { "ru": "Компания выиграла тендер на проект стоимостью 50 миллионов благодаря техническим преимуществам и конкурентной цене.", "en": "The company won the 50 million project bid thanks to its technical advantages and reasonable pricing." }, "difficulty": "hard" }] },
  { "chinese": "经济", "pinyin": "jīngjì", "translations": { "ru": "экономика", "en": "economy, economics" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "中国经济发展很快。", "pinyin": "Zhōngguó jīngjì fāzhǎn hěn kuài.", "translation": { "ru": "Экономика Китая быстро развивается.", "en": "China's economy is developing rapidly." }, "difficulty": "easy" }, { "chinese": "全球经济一体化使各国之间的贸易往来日益密切。", "pinyin": "Quánqiú jīngjì yītǐhuà shǐ gè guó zhījiān de màoyì wǎnglái rìyì mìqiè.", "translation": { "ru": "Глобализация экономики делает торговые связи между странами всё более тесными.", "en": "Economic globalization has made trade between countries increasingly close." }, "difficulty": "hard" }] },
  { "chinese": "增长", "pinyin": "zēngzhǎng", "translations": { "ru": "рост, прирост", "en": "growth, to grow" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "销售额增长了很多。", "pinyin": "Xiāoshòu'é zēngzhǎngle hěn duō.", "translation": { "ru": "Объём продаж значительно вырос.", "en": "Sales have grown a lot." }, "difficulty": "easy" }, { "chinese": "尽管面临诸多挑战，公司仍然保持了百分之十二的年增长率。", "pinyin": "Jǐnguǎn miànlín zhūduō tiǎozhàn, gōngsī réngrán bǎochíle bǎifēn zhī shí'èr de nián zēngzhǎnglǜ.", "translation": { "ru": "Несмотря на многочисленные вызовы, компания сохранила годовой темп роста 12%.", "en": "Despite facing many challenges, the company maintained a 12% annual growth rate." }, "difficulty": "hard" }] },
  { "chinese": "衰退", "pinyin": "shuāituì", "translations": { "ru": "спад, рецессия", "en": "recession, decline" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "经济出现了衰退。", "pinyin": "Jīngjì chūxiànle shuāituì.", "translation": { "ru": "В экономике наблюдается спад.", "en": "The economy is experiencing a recession." }, "difficulty": "medium" }, { "chinese": "全球经济衰退导致大量企业倒闭，失业率大幅上升。", "pinyin": "Quánqiú jīngjì shuāituì dǎozhì dàliàng qǐyè dǎobì, shīyèlǜ dàfú shàngshēng.", "translation": { "ru": "Мировая рецессия привела к массовым банкротствам предприятий и резкому росту безработицы.", "en": "The global economic recession led to massive business closures and a sharp rise in unemployment." }, "difficulty": "hard" }] },
  { "chinese": "通货膨胀", "pinyin": "tōnghuò péngzhàng", "translations": { "ru": "инфляция", "en": "inflation" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "通货膨胀越来越严重了。", "pinyin": "Tōnghuò péngzhàng yuèláiyuè yánzhòng le.", "translation": { "ru": "Инфляция становится всё серьёзнее.", "en": "Inflation is getting worse and worse." }, "difficulty": "medium" }, { "chinese": "为了抑制通货膨胀，央行采取了提高利率和收紧货币供应等措施。", "pinyin": "Wèile yìzhì tōnghuò péngzhàng, yāngháng cǎiqǔle tígāo lìlǜ hé shōujǐn huòbì gōngyìng děng cuòshī.", "translation": { "ru": "Для сдерживания инфляции центральный банк повысил ставки и ужесточил денежно-кредитную политику.", "en": "To curb inflation, the central bank raised interest rates and tightened the money supply." }, "difficulty": "hard" }] },
  { "chinese": "供需", "pinyin": "gōngxū", "translations": { "ru": "спрос и предложение", "en": "supply and demand" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "价格由供需决定。", "pinyin": "Jiàgé yóu gōngxū juédìng.", "translation": { "ru": "Цена определяется спросом и предложением.", "en": "Price is determined by supply and demand." }, "difficulty": "medium" }, { "chinese": "供需失衡导致某些商品价格暴涨，政府不得不采取价格调控措施。", "pinyin": "Gōngxū shīhéng dǎozhì mǒuxiē shāngpǐn jiàgé bàozhǎng, zhèngfǔ bùdébù cǎiqǔ jiàgé tiáokòng cuòshī.", "translation": { "ru": "Дисбаланс спроса и предложения привёл к резкому росту цен на некоторые товары, и правительству пришлось ввести ценовое регулирование.", "en": "Supply-demand imbalance caused some commodity prices to surge, forcing the government to implement price controls." }, "difficulty": "hard" }] },
  { "chinese": "消费", "pinyin": "xiāofèi", "translations": { "ru": "потребление, расходы", "en": "consumption, to consume" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "中国消费者的消费习惯正在改变。", "pinyin": "Zhōngguó xiāofèizhě de xiāofèi xíguàn zhèngzài gǎibiàn.", "translation": { "ru": "Потребительские привычки китайских покупателей меняются.", "en": "Chinese consumers' spending habits are changing." }, "difficulty": "medium" }, { "chinese": "促进内需消费是推动经济增长的重要手段之一。", "pinyin": "Cùjìn nèixū xiāofèi shì tuīdòng jīngjì zēngzhǎng de zhòngyào shǒuduàn zhī yī.", "translation": { "ru": "Стимулирование внутреннего потребления — один из ключевых способов содействия экономическому росту.", "en": "Promoting domestic consumption is one of the important means of driving economic growth." }, "difficulty": "hard" }] },
  { "chinese": "零售", "pinyin": "língshòu", "translations": { "ru": "розничная торговля", "en": "retail" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "这家店做零售生意。", "pinyin": "Zhè jiā diàn zuò língshòu shēngyì.", "translation": { "ru": "Этот магазин занимается розничной торговлей.", "en": "This store does retail business." }, "difficulty": "easy" }, { "chinese": "传统零售行业正面临来自电子商务的巨大竞争压力。", "pinyin": "Chuántǒng língshòu hángyè zhèng miànlín láizì diànzǐ shāngwù de jùdà jìngzhēng yālì.", "translation": { "ru": "Традиционная розничная торговля испытывает огромное конкурентное давление со стороны электронной коммерции.", "en": "The traditional retail industry is facing enormous competitive pressure from e-commerce." }, "difficulty": "hard" }] },
  { "chinese": "批发", "pinyin": "pīfā", "translations": { "ru": "оптовая торговля", "en": "wholesale" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "这个市场主要做批发。", "pinyin": "Zhège shìchǎng zhǔyào zuò pīfā.", "translation": { "ru": "Этот рынок в основном занимается оптом.", "en": "This market mainly does wholesale." }, "difficulty": "easy" }, { "chinese": "我们在义乌批发市场找到了价格最优惠的供货渠道。", "pinyin": "Wǒmen zài Yìwū pīfā shìchǎng zhǎodàole jiàgé zuì yōuhuì de gōnghuò qúdào.", "translation": { "ru": "На оптовом рынке в Иу мы нашли самый выгодный канал поставок.", "en": "We found the most favorable supply channels at the Yiwu wholesale market." }, "difficulty": "hard" }] },
  { "chinese": "电商", "pinyin": "diànshāng", "translations": { "ru": "электронная коммерция", "en": "e-commerce" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "电商行业发展很快。", "pinyin": "Diànshāng hángyè fāzhǎn hěn kuài.", "translation": { "ru": "Индустрия электронной коммерции быстро развивается.", "en": "The e-commerce industry is developing rapidly." }, "difficulty": "easy" }, { "chinese": "越来越多的传统企业开始布局电商渠道，实现线上线下融合发展。", "pinyin": "Yuèláiyuè duō de chuántǒng qǐyè kāishǐ bùjú diànshāng qúdào, shíxiàn xiànshàng xiànxià rónghé fāzhǎn.", "translation": { "ru": "Всё больше традиционных предприятий выходят в электронную коммерцию, объединяя онлайн и офлайн торговлю.", "en": "More and more traditional enterprises are expanding into e-commerce channels, integrating online and offline development." }, "difficulty": "hard" }] },
  { "chinese": "网购", "pinyin": "wǎnggòu", "translations": { "ru": "онлайн-покупки", "en": "online shopping" }, "difficulty": "easy", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "我经常在网上网购。", "pinyin": "Wǒ jīngcháng zài wǎngshàng wǎnggòu.", "translation": { "ru": "Я часто покупаю в интернете.", "en": "I often shop online." }, "difficulty": "easy" }, { "chinese": "双十一期间，各大电商平台的网购成交额再创新高。", "pinyin": "Shuāng shíyī qījiān, gè dà diànshāng píngtái de wǎnggòu chéngjiāo'é zài chuàng xīn gāo.", "translation": { "ru": "В период «Дня холостяков» объём онлайн-продаж на крупнейших платформах снова побил рекорд.", "en": "During Double 11, online shopping transaction volumes on major platforms hit new highs again." }, "difficulty": "hard" }] },
  { "chinese": "风险", "pinyin": "fēngxiǎn", "translations": { "ru": "риск", "en": "risk" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "投资有风险。", "pinyin": "Tóuzī yǒu fēngxiǎn.", "translation": { "ru": "Инвестиции сопряжены с рисками.", "en": "Investment involves risks." }, "difficulty": "easy" }, { "chinese": "企业在拓展海外市场时需要充分评估政治、法律和汇率等方面的风险。", "pinyin": "Qǐyè zài tuòzhǎn hǎiwài shìchǎng shí xūyào chōngfèn pínggū zhèngzhì, fǎlǜ hé huìlǜ děng fāngmiàn de fēngxiǎn.", "translation": { "ru": "При выходе на зарубежные рынки предприятию необходимо тщательно оценить политические, правовые и валютные риски.", "en": "When expanding into overseas markets, enterprises need to fully assess political, legal, and exchange rate risks." }, "difficulty": "hard" }] },
  { "chinese": "评估", "pinyin": "pínggū", "translations": { "ru": "оценка", "en": "evaluation, assessment" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我们需要对项目进行评估。", "pinyin": "Wǒmen xūyào duì xiàngmù jìnxíng pínggū.", "translation": { "ru": "Нам нужно провести оценку проекта.", "en": "We need to evaluate the project." }, "difficulty": "medium" }, { "chinese": "第三方评估机构对公司资产进行了全面评估，估值约为三亿元。", "pinyin": "Dìsānfāng pínggū jīgòu duì gōngsī zīchǎn jìnxíngle quánmiàn pínggū, gūzhí yuē wéi sān yì yuán.", "translation": { "ru": "Независимая оценочная компания провела полную оценку активов компании, стоимость составила около 300 млн юаней.", "en": "A third-party assessment firm conducted a comprehensive evaluation of the company's assets, valued at approximately 300 million yuan." }, "difficulty": "hard" }] },
  { "chinese": "决策", "pinyin": "juécè", "translations": { "ru": "принятие решений", "en": "decision-making" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "领导需要做出决策。", "pinyin": "Lǐngdǎo xūyào zuòchū juécè.", "translation": { "ru": "Руководитель должен принять решение.", "en": "The leader needs to make a decision." }, "difficulty": "medium" }, { "chinese": "数据驱动的决策方式可以有效减少管理层凭经验做出错误判断的风险。", "pinyin": "Shùjù qūdòng de juécè fāngshì kěyǐ yǒuxiào jiǎnshǎo guǎnlǐcéng píng jīngyàn zuòchū cuòwù pànduàn de fēngxiǎn.", "translation": { "ru": "Принятие решений на основе данных позволяет снизить риск ошибочных суждений руководства, основанных на интуиции.", "en": "Data-driven decision-making can effectively reduce the risk of management making wrong judgments based on experience alone." }, "difficulty": "hard" }] },
  { "chinese": "领导", "pinyin": "lǐngdǎo", "translations": { "ru": "руководитель, руководство", "en": "leader, leadership" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "他是公司的领导。", "pinyin": "Tā shì gōngsī de lǐngdǎo.", "translation": { "ru": "Он руководитель компании.", "en": "He is the company's leader." }, "difficulty": "easy" }, { "chinese": "优秀的领导不仅要有远见，还要善于激励团队、凝聚人心。", "pinyin": "Yōuxiù de lǐngdǎo bùjǐn yào yǒu yuǎnjiàn, hái yào shànyú jīlì tuánduì, níngjù rénxīn.", "translation": { "ru": "Хороший руководитель должен не только обладать дальновидностью, но и уметь мотивировать команду и сплачивать людей.", "en": "An excellent leader must not only have vision but also be good at motivating the team and uniting people." }, "difficulty": "hard" }] },
  { "chinese": "管理", "pinyin": "guǎnlǐ", "translations": { "ru": "управление, менеджмент", "en": "management, to manage" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "他负责管理这个部门。", "pinyin": "Tā fùzé guǎnlǐ zhège bùmén.", "translation": { "ru": "Он отвечает за управление этим отделом.", "en": "He is responsible for managing this department." }, "difficulty": "easy" }, { "chinese": "现代企业管理强调扁平化组织结构和高效的信息流通机制。", "pinyin": "Xiàndài qǐyè guǎnlǐ qiángdiào biǎnpínghuà zǔzhī jiégòu hé gāoxiào de xìnxī liútōng jīzhì.", "translation": { "ru": "Современный менеджмент делает упор на плоскую организационную структуру и эффективный обмен информацией.", "en": "Modern business management emphasizes flat organizational structures and efficient information flow mechanisms." }, "difficulty": "hard" }] },
  { "chinese": "沟通", "pinyin": "gōutōng", "translations": { "ru": "коммуникация, общение", "en": "communication" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "沟通很重要。", "pinyin": "Gōutōng hěn zhòngyào.", "translation": { "ru": "Коммуникация очень важна.", "en": "Communication is very important." }, "difficulty": "easy" }, { "chinese": "跨部门沟通不畅是导致项目延期的主要原因之一。", "pinyin": "Kuà bùmén gōutōng bù chàng shì dǎozhì xiàngmù yánqī de zhǔyào yuányīn zhī yī.", "translation": { "ru": "Плохая коммуникация между отделами — одна из главных причин задержки проектов.", "en": "Poor cross-department communication is one of the main causes of project delays." }, "difficulty": "hard" }] },
  { "chinese": "会计", "pinyin": "kuàijì", "translations": { "ru": "бухгалтер, бухгалтерия", "en": "accountant, accounting" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "她是公司的会计。", "pinyin": "Tā shì gōngsī de kuàijì.", "translation": { "ru": "Она бухгалтер компании.", "en": "She is the company's accountant." }, "difficulty": "easy" }, { "chinese": "会计部门需要在每个季度结束后两周内完成财务报表的编制和审核。", "pinyin": "Kuàijì bùmén xūyào zài měige jìdù jiéshù hòu liǎng zhōu nèi wánchéng cáiwù bàobiǎo de biānzhì hé shěnhé.", "translation": { "ru": "Бухгалтерия должна подготовить и проверить финансовую отчётность в течение двух недель после окончания каждого квартала.", "en": "The accounting department needs to complete and review financial statements within two weeks after each quarter ends." }, "difficulty": "hard" }] },
  { "chinese": "财务", "pinyin": "cáiwù", "translations": { "ru": "финансы", "en": "finance, financial affairs" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "公司的财务状况很好。", "pinyin": "Gōngsī de cáiwù zhuàngkuàng hěn hǎo.", "translation": { "ru": "Финансовое состояние компании хорошее.", "en": "The company's financial situation is good." }, "difficulty": "easy" }, { "chinese": "财务总监向董事会提交了详细的年度财务分析报告。", "pinyin": "Cáiwù zǒngjiān xiàng dǒngshìhuì tíjiāole xiángxì de niándù cáiwù fēnxī bàogào.", "translation": { "ru": "Финансовый директор представил совету директоров подробный годовой финансовый отчёт.", "en": "The CFO submitted a detailed annual financial analysis report to the board of directors." }, "difficulty": "hard" }] },
  { "chinese": "资产", "pinyin": "zīchǎn", "translations": { "ru": "актив, имущество", "en": "asset" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司的资产在增长。", "pinyin": "Gōngsī de zīchǎn zài zēngzhǎng.", "translation": { "ru": "Активы компании растут.", "en": "The company's assets are growing." }, "difficulty": "easy" }, { "chinese": "公司的总资产包括固定资产、流动资产和无形资产三大类。", "pinyin": "Gōngsī de zǒng zīchǎn bāokuò gùdìng zīchǎn, liúdòng zīchǎn hé wúxíng zīchǎn sān dà lèi.", "translation": { "ru": "Совокупные активы компании включают основные средства, оборотные активы и нематериальные активы.", "en": "The company's total assets include fixed assets, current assets, and intangible assets." }, "difficulty": "hard" }] },
  { "chinese": "负债", "pinyin": "fùzhài", "translations": { "ru": "обязательства, пассив", "en": "liability, debt" }, "difficulty": "hard", "hskLevel": 6, "tags": ["business", "general"], "examples": [{ "chinese": "公司的负债太高了。", "pinyin": "Gōngsī de fùzhài tài gāo le.", "translation": { "ru": "Обязательства компании слишком велики.", "en": "The company's liabilities are too high." }, "difficulty": "easy" }, { "chinese": "资产负债表显示，公司的负债率已经超过了行业安全线。", "pinyin": "Zīchǎn fùzhài biǎo xiǎnshì, gōngsī de fùzhàilǜ yǐjīng chāoguòle hángyè ānquánxiàn.", "translation": { "ru": "Баланс показывает, что коэффициент задолженности компании превысил безопасный уровень по отрасли.", "en": "The balance sheet shows the company's debt ratio has exceeded the industry safety line." }, "difficulty": "hard" }] },
  { "chinese": "利益", "pinyin": "lìyì", "translations": { "ru": "выгода, интерес", "en": "benefit, interest" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "我们要保护股东的利益。", "pinyin": "Wǒmen yào bǎohù gǔdōng de lìyì.", "translation": { "ru": "Мы должны защищать интересы акционеров.", "en": "We must protect shareholders' interests." }, "difficulty": "medium" }, { "chinese": "企业在追求利润的同时，也应兼顾社会责任和各方利益相关者的诉求。", "pinyin": "Qǐyè zài zhuīqiú lìrùn de tóngshí, yě yīng jiāngù shèhuì zérèn hé gè fāng lìyì xiāngguānzhě de sùqiú.", "translation": { "ru": "Стремясь к прибыли, предприятие также должно учитывать социальную ответственность и интересы всех заинтересованных сторон.", "en": "While pursuing profits, enterprises should also consider social responsibility and stakeholder interests." }, "difficulty": "hard" }] },
  { "chinese": "业绩", "pinyin": "yèjì", "translations": { "ru": "результаты работы, показатели", "en": "performance, achievements" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "他的业绩很突出。", "pinyin": "Tā de yèjì hěn tūchū.", "translation": { "ru": "Его результаты работы очень выдающиеся.", "en": "His performance is outstanding." }, "difficulty": "easy" }, { "chinese": "销售部的业绩超额完成了年度目标，每个成员都获得了丰厚的奖金。", "pinyin": "Xiāoshòu bù de yèjì chāo'é wánchéngle niándù mùbiāo, měi ge chéngyuán dōu huòdéle fēnghòu de jiǎngjīn.", "translation": { "ru": "Отдел продаж перевыполнил годовой план, и каждый сотрудник получил щедрую премию.", "en": "The sales department exceeded its annual target, and each member received a generous bonus." }, "difficulty": "hard" }] },
  { "chinese": "绩效", "pinyin": "jìxiào", "translations": { "ru": "эффективность, KPI", "en": "performance, efficiency" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "公司实行绩效考核制度。", "pinyin": "Gōngsī shíxíng jìxiào kǎohé zhìdù.", "translation": { "ru": "Компания применяет систему оценки эффективности.", "en": "The company implements a performance evaluation system." }, "difficulty": "medium" }, { "chinese": "员工的绩效工资与季度考核结果直接挂钩，表现优秀者可获得额外奖励。", "pinyin": "Yuángōng de jìxiào gōngzī yǔ jìdù kǎohé jiéguǒ zhíjiē guàgōu, biǎoxiàn yōuxiùzhě kě huòdé éwài jiǎnglì.", "translation": { "ru": "Премиальная часть зарплаты напрямую привязана к результатам квартальной аттестации, лучшие сотрудники получают дополнительное вознаграждение.", "en": "Employees' performance-based pay is directly linked to quarterly evaluation results; top performers can receive extra rewards." }, "difficulty": "hard" }] },
  { "chinese": "考核", "pinyin": "kǎohé", "translations": { "ru": "аттестация, проверка", "en": "assessment, evaluation" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "年底会有一次考核。", "pinyin": "Niándǐ huì yǒu yī cì kǎohé.", "translation": { "ru": "В конце года будет аттестация.", "en": "There will be an assessment at year-end." }, "difficulty": "easy" }, { "chinese": "新的考核标准更加注重员工的创新能力和团队协作表现。", "pinyin": "Xīn de kǎohé biāozhǔn gèngjiā zhùzhòng yuángōng de chuàngxīn nénglì hé tuánduì xiézuò biǎoxiàn.", "translation": { "ru": "Новые критерии аттестации уделяют больше внимания инновационным способностям и навыкам командной работы сотрудников.", "en": "The new assessment criteria place more emphasis on employees' innovation ability and teamwork performance." }, "difficulty": "hard" }] },
  { "chinese": "方案", "pinyin": "fāng'àn", "translations": { "ru": "план, проект, схема", "en": "plan, proposal, scheme" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "你有什么好方案吗？", "pinyin": "Nǐ yǒu shénme hǎo fāng'àn ma?", "translation": { "ru": "У тебя есть хороший план?", "en": "Do you have a good plan?" }, "difficulty": "easy" }, { "chinese": "项目组提出了三个备选方案，管理层将在下周的会议上做最终决定。", "pinyin": "Xiàngmù zǔ tíchūle sān ge bèixuǎn fāng'àn, guǎnlǐcéng jiāng zài xià zhōu de huìyì shàng zuò zuìzhōng juédìng.", "translation": { "ru": "Проектная группа предложила три варианта, руководство примет окончательное решение на совещании на следующей неделе.", "en": "The project team proposed three alternative plans; management will make the final decision at next week's meeting." }, "difficulty": "hard" }] },
  { "chinese": "提案", "pinyin": "tí'àn", "translations": { "ru": "предложение, проект", "en": "proposal, motion" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "他提交了一个新提案。", "pinyin": "Tā tíjiāole yī ge xīn tí'àn.", "translation": { "ru": "Он представил новое предложение.", "en": "He submitted a new proposal." }, "difficulty": "easy" }, { "chinese": "这份提案详细阐述了新产品的市场定位、目标用户和推广计划。", "pinyin": "Zhè fèn tí'àn xiángxì chǎnshùle xīn chǎnpǐn de shìchǎng dìngwèi, mùbiāo yònghù hé tuīguǎng jìhuà.", "translation": { "ru": "В этом предложении подробно описаны позиционирование нового продукта на рынке, целевая аудитория и план продвижения.", "en": "This proposal elaborates on the new product's market positioning, target users, and promotion plan." }, "difficulty": "hard" }] },
  { "chinese": "产品", "pinyin": "chǎnpǐn", "translations": { "ru": "продукт, товар", "en": "product" }, "difficulty": "easy", "hskLevel": 3, "tags": ["business", "general"], "examples": [{ "chinese": "这个产品很受欢迎。", "pinyin": "Zhège chǎnpǐn hěn shòu huānyíng.", "translation": { "ru": "Этот продукт очень популярен.", "en": "This product is very popular." }, "difficulty": "easy" }, { "chinese": "产品经理负责从需求分析到上市推广的整个产品生命周期管理。", "pinyin": "Chǎnpǐn jīnglǐ fùzé cóng xūqiú fēnxī dào shàngshì tuīguǎng de zhěnggè chǎnpǐn shēngmìng zhōuqī guǎnlǐ.", "translation": { "ru": "Продуктовый менеджер отвечает за управление всем жизненным циклом продукта — от анализа потребностей до вывода на рынок.", "en": "The product manager is responsible for the entire product lifecycle from requirement analysis to market launch." }, "difficulty": "hard" }] },
  { "chinese": "效率", "pinyin": "xiàolǜ", "translations": { "ru": "эффективность, КПД", "en": "efficiency" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "我们要提高工作效率。", "pinyin": "Wǒmen yào tígāo gōngzuò xiàolǜ.", "translation": { "ru": "Нам нужно повысить эффективность работы.", "en": "We need to improve work efficiency." }, "difficulty": "easy" }, { "chinese": "引入项目管理工具后，团队的协作效率提高了将近百分之四十。", "pinyin": "Yǐnrù xiàngmù guǎnlǐ gōngjù hòu, tuánduì de xiézuò xiàolǜ tígāole jiāngjìn bǎifēn zhī sìshí.", "translation": { "ru": "После внедрения инструментов управления проектами эффективность командной работы выросла почти на 40%.", "en": "After introducing project management tools, team collaboration efficiency improved by nearly 40%." }, "difficulty": "hard" }] },
  { "chinese": "收益", "pinyin": "shōuyì", "translations": { "ru": "доход, прибыль", "en": "earnings, returns, revenue" }, "difficulty": "medium", "hskLevel": 5, "tags": ["business", "general"], "examples": [{ "chinese": "这笔投资的收益不错。", "pinyin": "Zhè bǐ tóuzī de shōuyì bú cuò.", "translation": { "ru": "Доходность этих инвестиций неплохая.", "en": "The returns on this investment are good." }, "difficulty": "easy" }, { "chinese": "长期来看，分散投资可以在降低风险的同时保持稳定的收益水平。", "pinyin": "Chángqī lái kàn, fēnsàn tóuzī kěyǐ zài jiàngdī fēngxiǎn de tóngshí bǎochí wěndìng de shōuyì shuǐpíng.", "translation": { "ru": "В долгосрочной перспективе диверсификация инвестиций позволяет снизить риски, сохраняя стабильную доходность.", "en": "In the long run, diversified investment can reduce risks while maintaining stable returns." }, "difficulty": "hard" }] },
  { "chinese": "责任", "pinyin": "zérèn", "translations": { "ru": "ответственность", "en": "responsibility" }, "difficulty": "medium", "hskLevel": 4, "tags": ["business", "general"], "examples": [{ "chinese": "这是我的责任。", "pinyin": "Zhè shì wǒ de zérèn.", "translation": { "ru": "Это моя ответственность.", "en": "This is my responsibility." }, "difficulty": "easy" }, { "chinese": "企业社会责任不仅包括环境保护，还涉及员工权益和社区回馈。", "pinyin": "Qǐyè shèhuì zérèn bùjǐn bāokuò huánjìng bǎohù, hái shèjí yuángōng quányì hé shèqū huífù.", "translation": { "ru": "Корпоративная социальная ответственность включает не только охрану окружающей среды, но и защиту прав сотрудников и вклад в развитие общества.", "en": "Corporate social responsibility includes not only environmental protection but also employee rights and community contributions." }, "difficulty": "hard" }] }
